INSERT INTO municipalities (id, slug, name, region, short_description, hero_image_id, created_at, updated_at) VALUES (1, 'herceg-novi', 'Herceg Novi', 'coast', 'Gateway to the Bay of Kotor. A sun-drenched Mediterranean town of fortresses, botanical gardens, and pebble beaches nestled between mountains and sea. Known as the City of Sun and Mimosas.', NULL, '2026-04-07 21:16:13', '2026-04-07 21:16:13');
INSERT INTO municipalities (id, slug, name, region, short_description, hero_image_id, created_at, updated_at) VALUES (2, 'kotor', 'Kotor', 'coast', 'UNESCO World Heritage jewel at the head of Europe''s southernmost fjord. Medieval walled town with 1350-step fortress climb, baroque Perast, and the man-made island of Our Lady of the Rocks.', NULL, '2026-04-07 21:16:13', '2026-04-07 21:16:13');
INSERT INTO municipalities (id, slug, name, region, short_description, hero_image_id, created_at, updated_at) VALUES (3, 'tivat', 'Tivat', 'coast', 'Montenegro''s marina town. Home to the luxury Porto Montenegro superyacht marina, Island of Flowers botanical garden, and sandy Plavi Horizonti beach on the Lustica peninsula.', NULL, '2026-04-07 21:16:13', '2026-04-07 21:16:13');
INSERT INTO municipalities (id, slug, name, region, short_description, hero_image_id, created_at, updated_at) VALUES (4, 'budva', 'Budva', 'coast', 'The Montenegrin Riviera''s beating heart. A 2500-year-old walled town surrounded by golden beaches, vibrant nightlife, and the iconic island of Sveti Stefan.', NULL, '2026-04-07 21:16:13', '2026-04-07 21:16:13');
INSERT INTO municipalities (id, slug, name, region, short_description, hero_image_id, created_at, updated_at) VALUES (5, 'bar', 'Bar', 'coast', 'Where Mediterranean meets the mountains. Explore the atmospheric ruins of Stari Bar, the 2000-year-old Olive Tree, Ottoman aqueducts, and the Crmnica wine region.', NULL, '2026-04-07 21:16:13', '2026-04-07 21:16:13');
INSERT INTO municipalities (id, slug, name, region, short_description, hero_image_id, created_at, updated_at) VALUES (6, 'ulcinj', 'Ulcinj', 'coast', 'Montenegro''s southernmost gem with 13km of sandy coastline. Discover the Old Town citadel, kite-surfing on Velika Plaza, the nature reserve of Ada Bojana, and Sas Lake bird sanctuary.', NULL, '2026-04-07 21:16:13', '2026-04-07 21:16:13');
