INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (1, 'herceg-novi-zanjice-beach', 'Žanjice Beach', '[]'::jsonb, 1, 1, NULL, 42.3933, 18.5689, 'Popular pebble beach on the Luštica peninsula, accessible by boat or car. Crystal clear water and nearby Blue Grotto.', 'Žanjice is the premier beach on the Luštica Peninsula, featuring white pebbles and turquoise waters in a sheltered bay. The beach serves as the main gateway to the famous Blue Cave (Plava Špilja), with boat trips departing regularly from the shore. Accessible by car via the Luštica road or by water taxi from Herceg Novi. Sun lounger and umbrella rental is available, along with several beach restaurants serving fresh seafood. Parking is available above the beach but fills quickly in peak season - arriving before 10 AM is recommended.', '["beach", "swimming", "boat-access"]'::jsonb, '["sunbed-rental", "restaurant", "bar", "boat-trips", "parking", "snorkeling"]'::jsonb, '["swimming", "snorkeling", "day-trip"]'::jsonb, TRUE, 90, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://www.hercegnovi.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:13', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (2, 'herceg-novi-miriste-beach', 'Mirište Beach', '[]'::jsonb, 1, 1, NULL, 42.3897, 18.5641, 'Secluded pebble beach near Žanjice, surrounded by lush Mediterranean vegetation.', 'Mirište is a secluded pebble beach just around the headland from Žanjice, surrounded by lush Mediterranean vegetation that provides natural shade. The beach is less crowded than its neighbor and retains a more peaceful atmosphere. Access is via a short walking path from Žanjice or directly by boat. The clear water is excellent for snorkeling around the rocky edges. Basic refreshments are available from a small seasonal beach bar.', '["beach", "secluded", "nature"]'::jsonb, '["seasonal-bar", "natural-shade", "snorkeling"]'::jsonb, '["swimming", "snorkeling", "tranquility"]'::jsonb, FALSE, 70, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', FALSE, FALSE, NULL, 'https://www.hercegnovi.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:13', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (3, 'herceg-novi-savina-beach', 'Savina Beach', '[]'::jsonb, 1, 1, NULL, 42.4553, 18.5378, 'Small pebble beach near the Savina Monastery. Calm waters ideal for families.', 'A small, family-friendly pebble beach located near the beautiful Savina Monastery complex. The calm, sheltered waters of the inner bay make it ideal for young children. The nearby monastery (dating to the 11th century) with its precious icons and lush gardens provides a cultural complement to the beach visit. A small beach bar operates in summer. The beach is within walking distance of several Savina restaurants.', '[]'::jsonb, '["beach-bar", "calm-water", "monastery-nearby"]'::jsonb, '["families", "swimming"]'::jsonb, FALSE, 60, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://www.hercegnovi.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:13', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (4, 'herceg-novi-igalo-riviera', 'Igalo Riviera', '[]'::jsonb, 1, 1, NULL, 42.4571, 18.5101, 'Long promenade beach in Igalo, known for therapeutic mud and mineral springs. Home to the Institute Dr Simo Milošević.', 'Igalo''s beach stretches along a pleasant promenade in the westernmost part of Herceg Novi, renowned for its therapeutic mud and mineral springs. The Institute Dr Simo Milošević, a major rehabilitation center, sits along the beach and has attracted wellness visitors for decades. The sandy bottom and shallow water (especially near Tito''s Villa at the far end) make it one of the best family beaches in the bay. Numerous cafes, restaurants, and ice cream shops line the promenade. The beach area is flat and fully accessible.', '["wellness", "promenade", "therapeutic"]'::jsonb, '["promenade", "cafes", "restaurants", "therapeutic-mud", "mineral-springs", "flat-access", "shallow-water"]'::jsonb, '["families", "wellness", "swimming"]'::jsonb, TRUE, 80, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://www.hercegnovi.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:13', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (5, 'herceg-novi-blue-grotto-plava-spilja', 'Blue Grotto (Plava Špilja)', '[]'::jsonb, 1, 1, NULL, 42.3889, 18.5594, 'Natural sea cave near Žanjice with stunning blue light effects. Accessible by boat.', 'The Blue Grotto is a natural sea cave near Žanjice where sunlight refracts through the underwater entrance creating stunning blue light effects on the cave walls and water. Accessible only by boat, tours depart regularly from Herceg Novi, Žanjice, and other bay locations. The best time to visit is in the morning when sunlight creates the most vivid blue glow. Swimming inside the cave is permitted and unforgettable. Boat tours typically combine the Blue Grotto with stops at nearby beaches. Speedboat tours cost approximately 25-40 EUR.', '["cave", "boat-trip", "nature"]'::jsonb, '["boat-access", "swimming-in-cave"]'::jsonb, '["boat-tour", "photography"]'::jsonb, TRUE, 85, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.hercegnovi.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:13', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (6, 'herceg-novi-kanli-kula-fortress', 'Kanli Kula Fortress', '[]'::jsonb, 1, 3, NULL, 42.4531, 18.5372, 'Ottoman-era fortress and open-air theatre overlooking the bay. Hosts summer film and theatre festivals.', 'Built by the Ottoman Turks in 1539 and expanded by the Venetians in 1687, Kanli Kula (meaning ''Bloody Tower'') served as a prison during Ottoman rule. Today the massive fortress has been transformed into an atmospheric open-air amphitheater hosting summer film screenings, theatre performances, and cultural festivals. The fortress offers commanding views over the Bay of Kotor and the old town below. A small entrance fee applies. The steep climb up from the old town is rewarded with spectacular panoramas.', '["fortress", "ottoman", "theatre"]'::jsonb, '["amphitheater", "cultural-events", "panoramic-views"]'::jsonb, '["history", "cultural-events", "photography"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, FALSE, FALSE, NULL, 'https://www.hercegnovi.travel/en/fortresses', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (7, 'herceg-novi-forte-mare', 'Forte Mare', '["Forte Mare", "\u0424\u043e\u0440\u0442\u0435 \u041c\u0430\u0440\u0435"]'::jsonb, 1, 3, NULL, 42.4523, 18.5383, 'Seaside fortress at the entrance to the old town. Built in the 14th century, now a venue for cultural events.', 'Forte Mare guards the entrance to Herceg Novi''s old town from the sea side, built in the 14th century and subsequently modified by each power that controlled the city. Today it serves as a venue for cultural events, art exhibitions, and summer concerts. The fortress includes a sea-level swimming platform popular with locals and an upper terrace with panoramic views. Small entrance fee for the upper fortress. One of the most photographed buildings in Herceg Novi.', '["fortress", "medieval", "seaside"]'::jsonb, '["cultural-events", "swimming-platform", "exhibitions"]'::jsonb, '["history", "photography", "swimming"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, FALSE, FALSE, NULL, 'https://www.hercegnovi.travel/en/fortresses', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (8, 'herceg-novi-spanjola-fortress', 'Španjola Fortress', '[]'::jsonb, 1, 3, NULL, 42.4537, 18.539, 'Spanish-built fortress on the hill above the old town. Panoramic views of the entire Bay of Kotor.', 'The Spanish Fortress sits at the highest point above Herceg Novi''s old town, built during the brief Spanish occupation in the early 16th century. The climb up through the old town''s narrow streets and stone staircases is steep but rewarding - the fortress offers the most comprehensive panoramic views in the city, encompassing the entire Bay of Kotor, the open sea, and the surrounding mountains. Currently undergoing intermittent restoration, check locally for access status.', '["fortress", "panorama", "spanish"]'::jsonb, '["panoramic-views"]'::jsonb, '["photography", "panoramic-views"]'::jsonb, TRUE, 70, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, FALSE, FALSE, NULL, 'https://www.hercegnovi.travel/en/fortresses', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (9, 'herceg-novi-savina-monastery', 'Savina Monastery', '["\u041c\u0430\u043d\u0430\u0441\u0442\u0438\u0440 \u0421\u0430\u0432\u0438\u043d\u0430", "Savina", "Monastero Savina"]'::jsonb, 1, 4, NULL, 42.4544, 18.5403, 'Serbian Orthodox monastery complex dating to the 11th century, set in lush gardens overlooking the bay. Houses precious icons and manuscripts.', 'The Savina Monastery is one of the most important Serbian Orthodox religious sites on the Adriatic, comprising a complex of churches dating from the 11th to 18th centuries set in magnificent Mediterranean gardens. The Small Church (11th century) contains medieval frescoes, while the Large Church (18th century) houses the precious Savina icon and valuable manuscripts. The monastery''s lush botanical gardens cascade down the hillside toward the bay, offering peaceful walks among exotic plants. Free entry; modest dress required.', '["monastery", "orthodox", "medieval"]'::jsonb, '["gardens", "museum", "free-entry"]'::jsonb, '["history", "culture", "photography"]'::jsonb, TRUE, 90, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, FALSE, NULL, 'https://www.hercegnovi.travel/en/monasteries-and-churches', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:05:29');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (10, 'herceg-novi-herceg-novi-botanical-garden', 'Herceg Novi Botanical Garden', '[]'::jsonb, 1, 6, NULL, 42.452, 18.5365, 'Mediterranean botanical garden with subtropical and tropical plants. Terraced gardens with bay views.', 'This terraced Mediterranean garden above the old town features an impressive collection of subtropical and tropical plants, many brought by Herceg Novi''s seafaring merchants over centuries. The garden cascades down the hillside in a series of terraces, each offering different plant species and bay views. Mimosa trees bloom spectacularly in February, and the garden is at its most colorful in spring. The peaceful atmosphere provides a welcome retreat from the summer heat. Small entrance fee.', '["garden", "botany", "nature"]'::jsonb, '["terraced-paths", "bay-views", "shade"]'::jsonb, '["nature", "photography", "relaxation"]'::jsonb, FALSE, 65, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.hercegnovi.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (11, 'kotor-kotor-old-town', 'Kotor Old Town', '[]'::jsonb, 2, 3, NULL, 42.4247, 18.7712, 'UNESCO World Heritage medieval walled town. Labyrinth of narrow streets, Romanesque churches, and Venetian palaces at the head of the bay.', 'Kotor''s UNESCO-listed medieval walled town is one of the best-preserved medieval cities in the Mediterranean. Enter through the main Sea Gate (Vrata od Mora) to discover a labyrinth of narrow cobblestone streets, Romanesque churches, Venetian palaces, and charming squares. Key sights include St. Tryphon Cathedral, the Maritime Museum, Clock Tower, and numerous churches. The famous Kotor cats appear on every corner, with a dedicated Cat Museum. The town fills with cruise ship visitors during the day (10 AM - 4 PM); early morning and evening visits offer a more intimate experience.', '["unesco", "medieval", "venetian", "old-town"]'::jsonb, '["restaurants", "shops", "museums", "churches", "tourist-info"]'::jsonb, '["sightseeing", "history", "photography"]'::jsonb, TRUE, 100, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, TRUE, NULL, 'https://kotor.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (12, 'kotor-kotor-fortress-san-giovanni', 'Kotor Fortress (San Giovanni)', '[]'::jsonb, 2, 3, NULL, 42.4268, 18.7742, 'Fortified walls climbing 1200 meters to the Castle of San Giovanni. 1350 steps with breathtaking views of Boka Bay.', 'The fortifications climb 1,200 meters from the old town to the Castle of San Giovanni at 280 meters elevation, requiring approximately 1,350 steps. The climb takes 45-90 minutes depending on fitness. Multiple viewpoints along the route offer increasingly dramatic panoramas of Boka Bay. Entrance fee is charged at the old town trailhead (free if starting from the Ladder of Kotor at the back). Bring plenty of water, wear proper shoes, and avoid climbing during midday heat. The Church of Our Lady of Health provides a rest stop partway up.', '["fortress", "hiking", "panorama", "medieval"]'::jsonb, '["viewpoints", "church-midway"]'::jsonb, '["hiking", "photography", "sunset"]'::jsonb, TRUE, 95, FALSE, FALSE, FALSE, TRUE, TRUE, NULL, TRUE, FALSE, NULL, 'https://kotor.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (13, 'kotor-cathedral-of-saint-tryphon', 'Cathedral of Saint Tryphon', '[]'::jsonb, 2, 4, NULL, 42.4247, 18.7713, 'Romanesque cathedral built in 1166, the most prominent building in Kotor''s old town. Contains precious relics and medieval frescoes.', 'Kotor''s most iconic building, the Romanesque Cathedral of Saint Tryphon was first built in 1166 and reconstructed after earthquakes. The twin bell towers (not matching due to earthquake damage) are Kotor''s most recognizable silhouette. Inside, 14th-century frescoes, a medieval ciborium (canopy over the altar), and the treasury containing Saint Tryphon''s relics and golden religious objects await visitors. The cathedral is an active place of worship; entrance fee for tourists with modest dress required.', '["cathedral", "romanesque", "medieval"]'::jsonb, '["guided-tours", "treasury"]'::jsonb, '["history", "culture", "architecture"]'::jsonb, TRUE, 90, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, FALSE, NULL, 'https://kotor.travel/en/culture-and-history', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (14, 'kotor-perast', 'Perast', '["Perasto", "\u041f\u0435\u0440\u0430\u0441\u0442"]'::jsonb, 2, 2, NULL, 42.4869, 18.6978, 'Tiny baroque town on the Bay of Kotor, with 16 churches and 17 palaces. Starting point for boats to Our Lady of the Rocks.', 'Perast is a tiny baroque jewel on the Bay of Kotor with 16 churches and 17 palaces - remarkable for a town that never had more than a few hundred residents. The Venetian-era palaces line the waterfront, and the town serves as the departure point for boats to Our Lady of the Rocks island (5 EUR round trip, 5 minutes). The Perast Museum in the Bujović Palace documents the town''s distinguished naval history. Visit early morning or late afternoon to avoid day-trip crowds. Free to walk around; small fees for museum and island church.', '["baroque", "venetian", "bay"]'::jsonb, '["museum", "boat-trips", "restaurants", "waterfront-promenade"]'::jsonb, '["sightseeing", "boat-trip", "photography"]'::jsonb, TRUE, 95, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, TRUE, NULL, 'https://kotor.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:05:50');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (15, 'kotor-our-lady-of-the-rocks', 'Our Lady of the Rocks', '["Muttergottes von \u0160krpjela", "Madonna dello Scalpello", "\u0413\u043e\u0441\u043f\u0430 \u043e\u0434 \u0428\u043a\u0440\u043f\u0458\u0435\u043b\u0430"]'::jsonb, 2, 2, NULL, 42.487, 18.6885, 'Man-made island with a 15th-century church, created by locals who threw rocks into the sea over centuries. Museum with Tripo Kokolja paintings.', 'This man-made island was created over centuries by local sailors who followed a tradition of dropping a rock in the sea upon each safe return. The 15th-century Church of Our Lady of the Rocks contains 68 paintings by 17th-century Baroque artist Tripo Kokolja, silver votive tablets from grateful sailors, and a fascinating tapestry woven over 25 years by a local woman using gold thread and her own hair. The small museum charges a modest entrance fee. Boats depart every 30 minutes from Perast''s waterfront (5 EUR return).', '["island", "church", "museum", "unique"]'::jsonb, '["museum", "church", "boat-access"]'::jsonb, '["history", "culture", "boat-trip"]'::jsonb, TRUE, 95, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, FALSE, FALSE, NULL, 'https://kotor.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:05:48');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (16, 'kotor-maritime-museum-of-montenegro', 'Maritime Museum of Montenegro', '[]'::jsonb, 2, 5, NULL, 42.4248, 18.7708, 'Museum housed in a baroque palace in Kotor''s old town, documenting the rich maritime history of Boka Bay.', 'Housed in the Grgurina Palace, a baroque building in the heart of Kotor''s old town, the Maritime Museum chronicles the rich seafaring history of Boka Bay through three floors of exhibits. Collections include ship models, naval uniforms, navigational instruments, weapons, and portraits of famous Bay captains. The museum provides essential context for understanding why this small bay produced some of the Mediterranean''s greatest sailors. Allow 1-2 hours for a thorough visit.', '["museum", "maritime", "history"]'::jsonb, '["exhibits", "gift-shop"]'::jsonb, '["history", "culture", "rainy-day"]'::jsonb, TRUE, 70, TRUE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, FALSE, NULL, 'https://kotor.travel/en/culture-and-history', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (17, 'kotor-bajova-kula-beach', 'Bajova Kula Beach', '[]'::jsonb, 2, 1, NULL, 42.423, 18.768, 'Small beach just outside Kotor''s old town walls. Convenient location with views of the fortifications.', 'A small but convenient pebble beach located just outside Kotor''s old town walls, offering views of the medieval fortifications rising above. The beach has basic facilities including sun lounger rental and a seasonal cafe. Its proximity to the old town makes it the easiest swimming option for visitors staying in Kotor center. The water is calm and clean, though the beach gets busy when cruise ships are in port.', '[]'::jsonb, '["sunbed-rental", "cafe", "old-town-proximity"]'::jsonb, '["swimming", "convenience"]'::jsonb, FALSE, 60, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://kotor.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (18, 'kotor-morinj-beach', 'Morinj Beach', '[]'::jsonb, 2, 1, NULL, 42.4894, 18.6528, 'Quiet pebble beach in the village of Morinj, Bay of Kotor. Known for its restaurants and the freshwater Sopot waterfall nearby.', 'Quiet pebble beach in the village of Morinj on the inner part of Boka Bay. The area is known for the freshwater Sopot waterfall that flows into the bay nearby, creating interesting temperature variations in the swimming water. Several excellent restaurants (including the renowned Ćatovića Mlini) make Morinj an ideal destination for combining beach time with a memorable meal. The village is peaceful and authentically Montenegrin, with stone houses and Mediterranean vegetation.', '[]'::jsonb, '["restaurants", "waterfall-nearby", "parking"]'::jsonb, '["swimming", "dining", "tranquility"]'::jsonb, FALSE, 55, TRUE, TRUE, FALSE, FALSE, FALSE, 'pebble', TRUE, TRUE, NULL, 'https://kotor.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (19, 'kotor-vrmac-ridge-trail', 'Vrmac Ridge Trail', '[]'::jsonb, 2, 6, NULL, 42.44, 18.74, 'Mountain ridge trail between Kotor and Tivat offering panoramic views of both bays. Old Austrian fort at the summit.', 'The Vrmac Ridge offers a mountain hiking experience between Kotor and Tivat, with panoramic views of both bays from the summit of Saint Ilija peak (760m). The main trail starts at Trojica pass and follows the ridge through Mediterranean scrubland and past old Austrian fortifications. Fort Vrmac at 480m provides a dramatic rest stop with views. The full ridge walk takes 4-6 hours, but shorter sections are possible. Mountain biking tours also use these trails. Bring water, sun protection, and proper hiking shoes.', '["hiking", "trail", "panorama"]'::jsonb, '["marked-trails", "fort-viewpoint"]'::jsonb, '["hiking", "panoramic-views", "fitness"]'::jsonb, FALSE, 75, TRUE, FALSE, FALSE, TRUE, FALSE, NULL, TRUE, TRUE, NULL, 'https://kotor.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:11');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (20, 'kotor-ladder-of-kotor-kotor-serpentines', 'Ladder of Kotor (Kotor Serpentines)', '[]'::jsonb, 2, 6, NULL, 42.43, 18.775, 'Ancient zigzag trail climbing from Kotor to the village of Krstac, with stunning views at every turn. Historic mule path.', 'This ancient zigzag mule path climbs from behind Kotor''s old town to the village of Krstac at approximately 800 meters elevation, offering stunning views at every switchback. Originally a trade route, the stone-paved path is one of the most photogenic hikes in Montenegro. The climb takes 2-3 hours up and provides a free alternative route to the Kotor Fortress (entering from above rather than paying at the bottom). Best attempted in early morning to avoid heat. The path connects to the Vrmac Ridge for extended hikes.', '["hiking", "historic-trail", "panorama"]'::jsonb, '["marked-path", "viewpoints"]'::jsonb, '["hiking", "photography", "fitness"]'::jsonb, TRUE, 80, TRUE, FALSE, FALSE, TRUE, FALSE, NULL, TRUE, TRUE, NULL, 'https://kotor.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (21, 'tivat-porto-montenegro', 'Porto Montenegro', '[]'::jsonb, 3, 2, NULL, 42.4351, 18.6916, 'Luxury superyacht marina and waterfront village built on a former naval base. Shops, restaurants, and the Naval Heritage Collection museum.', 'Built on the site of the former Yugoslav Navy arsenal, Porto Montenegro is a luxury superyacht marina and lifestyle village that has transformed Tivat. The complex features 450 berths accommodating yachts up to 250 meters, designer boutiques, international restaurants, a pool club, and the Naval Heritage Collection museum. The waterfront promenade is free to walk and offers excellent people-watching. Events include yacht shows, regattas, and fashion events throughout the season. The marina village has become the social hub of the bay.', '["marina", "luxury", "shopping", "dining"]'::jsonb, '["restaurants", "shops", "marina", "pool-club", "museum", "events"]'::jsonb, '["dining", "shopping", "nightlife"]'::jsonb, TRUE, 90, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, TRUE, NULL, 'https://tivat.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (22, 'tivat-island-of-flowers-miholjska-prevlaka', 'Island of Flowers (Miholjska Prevlaka)', '[]'::jsonb, 3, 6, NULL, 42.4115, 18.6826, 'Small peninsula with a botanical garden, connected to the mainland by a short bridge. Medieval monastery ruins and diverse plant species.', 'Miholjska Prevlaka, locally called the Island of Flowers, is a small peninsula connected to the mainland by a short bridge, about 2 km south of Tivat center. The site contains ruins of a medieval Benedictine monastery, diverse Mediterranean and exotic plant species, and peaceful walking paths. The botanical diversity includes palms, cypresses, and flowering plants from around the world. The flat paths are suitable for families with strollers. Free entry. The island offers views across the bay toward Herceg Novi.', '["island", "garden", "monastery", "nature"]'::jsonb, '["walking-paths", "botanical-gardens", "monastery-ruins", "free-entry", "bay-views"]'::jsonb, '["nature", "families", "photography"]'::jsonb, TRUE, 80, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, TRUE, NULL, 'https://tivat.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (23, 'tivat-plavi-horizonti-beach', 'Plavi Horizonti Beach', '[]'::jsonb, 3, 1, NULL, 42.3786, 18.6853, 'One of the most beautiful sandy beaches in the Bay of Kotor, on the Luštica peninsula. Shallow water, ideal for families.', 'Often ranked as the best beach in the Bay of Kotor, Plavi Horizonti (Blue Horizons) is a 350-meter sandy beach in Pržno bay on the Luštica peninsula. The shallow, crystal-clear water warms quickly in summer, making it ideal for young children. The beach is backed by olive and pine groves providing natural shade. Sun loungers and umbrellas are available for rent, and a beach bar serves drinks and snacks. Parking is available but limited; arriving before 10 AM in summer is essential. The beach is about 15 minutes by car from Tivat.', '["sandy-beach", "family", "calm-water"]'::jsonb, '["sunbed-rental", "beach-bar", "natural-shade", "parking", "showers", "changing-rooms"]'::jsonb, '["families", "swimming", "relaxation"]'::jsonb, TRUE, 90, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://tivat.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (24, 'tivat-donja-lastva-beach', 'Donja Lastva Beach', '[]'::jsonb, 3, 1, NULL, 42.4167, 18.6833, 'Small pebbly beach in a charming historic village near Tivat. Quiet and less crowded.', 'A small pebbly beach in the charming historic village of Donja Lastva, just south of Tivat center. The village retains its traditional stone architecture and quiet atmosphere despite proximity to Porto Montenegro. The beach is less crowded than Tivat''s main beaches and offers a glimpse of authentic bay life. Several cafes in the village serve coffee and snacks. The old stone church and village square are worth exploring after your swim.', '[]'::jsonb, '["cafes", "village-charm"]'::jsonb, '["swimming", "tranquility", "local-experience"]'::jsonb, FALSE, 50, TRUE, TRUE, FALSE, FALSE, FALSE, 'pebble', TRUE, TRUE, NULL, 'https://tivat.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (25, 'tivat-ponta-beach', 'Ponta Beach', '[]'::jsonb, 3, 1, NULL, 42.4381, 18.6945, 'City beach right next to Porto Montenegro. Easy access, good facilities, and close to restaurants.', 'Tivat''s main city beach located right next to Porto Montenegro, Ponta offers the most convenient swimming option in town. The pebble beach has full facilities including sun lounger rental, showers, changing rooms, and is within steps of Porto Montenegro''s restaurants and cafes. The shallow gradient makes it suitable for families. The beach gets busy during peak season but the adjacent marina village provides plenty of shade and refreshment options.', '[]'::jsonb, '["sunbed-rental", "showers", "changing-rooms", "restaurants-nearby"]'::jsonb, '["swimming", "convenience", "families"]'::jsonb, FALSE, 65, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://tivat.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:14', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (26, 'tivat-naval-heritage-collection', 'Naval Heritage Collection', '[]'::jsonb, 3, 5, NULL, 42.4355, 18.692, 'Museum inside Porto Montenegro documenting the history of the Yugoslav Navy and the Tivat naval base.', 'Located inside Porto Montenegro, this museum documents the fascinating history of the Yugoslav Navy and the Tivat naval base that preceded the luxury marina. Exhibits include a preserved submarine (the P-821 Hero), torpedo boats, naval weapons, uniforms, and historical photographs documenting the transformation from military base to superyacht marina. The submarine tour is a highlight, especially for families with children. Allow 1-2 hours for a full visit. Small entrance fee.', '[]'::jsonb, '["submarine-tour", "exhibits", "gift-shop", "air-conditioning"]'::jsonb, '["history", "families", "rainy-day"]'::jsonb, TRUE, 55, TRUE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, FALSE, NULL, 'https://tivat.travel/en/culture', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (27, 'tivat-big-city-park-veliki-gradski-park', 'Big City Park (Veliki Gradski Park)', '[]'::jsonb, 3, 6, NULL, 42.434, 18.695, 'Large waterfront park in Tivat with diverse Mediterranean and exotic plant species, walking paths, and bay views.', 'Tivat''s central waterfront park spans a large area along the bay, featuring diverse Mediterranean and exotic plant species, well-maintained walking paths, and numerous benches with bay views. The park connects the city center to Porto Montenegro via a pleasant promenade. Children''s playgrounds, a seasonal outdoor cafe, and regular cultural events make it a gathering point for families. The flat, paved paths are fully accessible. Free entry.', '["park", "nature", "waterfront"]'::jsonb, '["playground", "cafes", "walking-paths", "benches", "bay-views", "flat-paths"]'::jsonb, '["families", "walking", "relaxation"]'::jsonb, FALSE, 60, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, TRUE, NULL, 'https://tivat.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (28, 'budva-budva-old-town-stari-grad', 'Budva Old Town (Stari Grad)', '[]'::jsonb, 4, 3, NULL, 42.2889, 18.8381, '2500-year-old walled Mediterranean town on a small peninsula. Narrow cobblestone streets, churches, citadela fortress, and seaside promenades.', 'Budva''s 2,500-year-old walled old town sits on a small peninsula jutting into the Adriatic. Within the medieval walls, narrow cobblestone streets wind between Venetian-era houses, past ancient churches (including the 9th-century Santa Maria in Punta and 7th-century St. John), art galleries, and buzzing restaurants and bars. The Citadela fortress at the southern tip offers rooftop panoramic views. By day the old town fills with tourists; by night it transforms into Montenegro''s most vibrant dining and nightlife district. Free to enter; Citadela charges a small fee.', '["old-town", "medieval", "nightlife", "dining"]'::jsonb, '["restaurants", "bars", "shops", "galleries", "citadela", "nightlife"]'::jsonb, '["sightseeing", "nightlife", "dining"]'::jsonb, TRUE, 95, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, TRUE, NULL, 'https://budva.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (29, 'budva-sveti-stefan', 'Sveti Stefan', '["\u0421\u0432\u0435\u0442\u0438 \u0421\u0442\u0435\u0444\u0430\u043d", "Santo Stefano"]'::jsonb, 4, 2, NULL, 42.2575, 18.8908, 'Iconic fortified island village connected to the mainland by a narrow isthmus. Former fishing village, now an exclusive Aman resort. Photographable from the beach.', 'Sveti Stefan is Montenegro''s most iconic landmark - a fortified island village connected to the mainland by a narrow sandy isthmus. Once a 15th-century fishing village, it was converted into an exclusive resort in the 1960s (hosted Marilyn Monroe, Sophia Loren) and is now operated by Aman Resorts. Non-guests cannot access the island, but the public beach on the southern side of the isthmus offers perfect views for photography. The viewpoint from the road above, especially at sunset, is one of the most photographed spots in the Balkans.', '["island", "iconic", "luxury", "photography"]'::jsonb, '["public-beach", "viewpoint", "photography"]'::jsonb, '["photography", "beach", "luxury"]'::jsonb, TRUE, 100, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://budva.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:07:27');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (30, 'budva-mogren-beach', 'Mogren Beach', '[]'::jsonb, 4, 1, NULL, 42.2908, 18.8331, 'Two connected pebble beaches west of the old town, accessed through a cliff tunnel. Beautiful setting between rocky cliffs.', 'Two connected pebble beaches west of Budva''s old town, accessed through a dramatic cliff tunnel carved through the rock. Mogren I (closer to town) has sun lounger rental and a beach bar. Mogren II (further) has an inflatable aqua park and more space. The beaches sit between towering rocky cliffs with Mediterranean vegetation above, creating a dramatic natural amphitheater. The dancer statue at the entrance is a popular photo spot. Access is via a 10-minute walk along a scenic cliffside path from the old town.', '["scenic", "cliff", "tunnel"]'::jsonb, '["sunbed-rental", "beach-bar", "aqua-park", "showers"]'::jsonb, '["swimming", "scenery"]'::jsonb, TRUE, 85, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', FALSE, FALSE, NULL, 'https://budva.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (31, 'budva-slovenska-plaza', 'Slovenska Plaza', '[]'::jsonb, 4, 1, NULL, 42.2869, 18.8419, 'The main city beach of Budva, stretching 1600 meters. Full facilities, water sports, and lively beach bars.', 'Budva''s main city beach stretches 1,600 meters along the waterfront east of the old town. The beach is divided into numerous sections, some free and some managed with sun lounger rental. A continuous strip of beach bars, restaurants, and shops lines the promenade behind the beach. Water sports including jet skiing, parasailing, and banana boats are available. The beach is most crowded during July-August when it''s the social epicenter of Montenegrin summer tourism. Water taxi boats depart for Sveti Nikola island.', '["city-beach", "facilities", "water-sports"]'::jsonb, '["sunbed-rental", "restaurants", "beach-bars", "water-sports", "water-taxi", "showers", "changing-rooms"]'::jsonb, '["swimming", "water-sports", "socializing"]'::jsonb, TRUE, 80, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://budva.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (32, 'budva-jaz-beach', 'Jaz Beach', '["\u0408\u0430\u0437", "Jaz"]'::jsonb, 4, 1, NULL, 42.2978, 18.8089, 'Large beach (1200m) west of Budva, famous for hosting major music festivals. Mix of sand and pebble sections.', 'One of Montenegro''s most famous beaches, Jaz stretches 1,200 meters in a wide bay west of Budva. The beach has two sections: a larger mixed sand-and-pebble section and a smaller nudist section behind a rocky outcrop. Jaz has hosted major music festivals including Sea Dance Festival (Best European Festival award). The beach has car parking (5 EUR in season), sun lounger rental, beach bars, and restaurants. A freshwater river creates a lagoon at the eastern end. Jaz is popular with both tourists and Budva locals on weekends.', '["festival", "large-beach", "music"]'::jsonb, '["parking", "sunbed-rental", "beach-bars", "restaurants", "water-sports", "festival-venue"]'::jsonb, '["festivals", "groups", "swimming"]'::jsonb, TRUE, 85, TRUE, FALSE, FALSE, FALSE, FALSE, 'mixed', TRUE, FALSE, NULL, 'https://budva.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:07:28');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (33, 'budva-becici-beach', 'Bečići Beach', '[]'::jsonb, 4, 1, NULL, 42.2808, 18.8542, 'Long sandy beach that once won the Grand Prix in Paris for the most beautiful beach in Europe. Excellent facilities.', 'This long sandy beach famously won the Grand Prix in Paris in 1935 for the most beautiful beach in Europe. The fine golden sand stretches nearly 2 km along a sweeping bay backed by major resort hotels. Full facilities include sun lounger rental, water sports, beach bars, and restaurants. The Mediteran hotel''s aqua park provides an additional family attraction. Bečići connects seamlessly to Budva via a tunnel and to Rafailovići along the beach. The beach offers excellent conditions for families with gradually shelving sand.', '["award-winning", "sandy", "resort"]'::jsonb, '["sunbed-rental", "water-sports", "beach-bars", "restaurants", "aqua-park-nearby", "showers", "lifeguard"]'::jsonb, '["families", "swimming", "water-sports"]'::jsonb, TRUE, 90, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://budva.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (34, 'budva-kamenovo-beach', 'Kamenovo Beach', '[]'::jsonb, 4, 1, NULL, 42.2753, 18.8583, 'Scenic pebble beach between Bečići and Rafailovići. Sheltered cove with pine trees and clear water.', 'A scenic pebble beach in a sheltered cove between Bečići and Rafailovići, framed by pine trees and rocky cliffs. The clear water is excellent for snorkeling, and the pine trees provide natural shade. A beach bar and restaurant operate in season. Access is via a steep staircase from the road above (approximately 100 steps). The beach is quieter than Bečići and Slovenska, offering a more relaxed atmosphere. Parking is available along the road above.', '["cove", "scenic", "pine-trees"]'::jsonb, '["beach-bar", "restaurant", "natural-shade", "snorkeling"]'::jsonb, '["swimming", "snorkeling", "relaxation"]'::jsonb, FALSE, 70, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://budva.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (35, 'budva-sveti-stefan-beach', 'Sveti Stefan Beach', '[]'::jsonb, 4, 1, NULL, 42.2578, 18.889, 'Pink-pebble beach facing the iconic Sveti Stefan island. Southern section is public, northern is for Aman guests.', 'The beach flanking the iconic Sveti Stefan island isthmus features distinctive pink pebbles that glow warmly in the afternoon sun. The beach is divided: the southern/public section is freely accessible (sun lounger rental available), while the northern section is reserved exclusively for Aman Resort guests. The public section offers unobstructed views of the medieval island village. The beach is one of the most photographed in the Mediterranean. A cafe at the entrance serves drinks and light meals.', '["iconic", "pink-pebble", "scenic"]'::jsonb, '["sunbed-rental", "cafe", "photography-spot"]'::jsonb, '["photography", "swimming", "scenery"]'::jsonb, TRUE, 90, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://budva.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (36, 'budva-ploce-beach', 'Ploče Beach', '[]'::jsonb, 4, 1, NULL, 42.2781, 18.86, 'Modern beach club with concrete platforms, pools, and a trendy atmosphere. Popular with younger visitors.', 'Ploče is not a traditional beach but a modern beach club complex with concrete platforms, swimming pools, and a trendy atmosphere. Multiple levels cascade down to the sea, with pools at different heights and direct sea access. The venue is popular with younger visitors seeking a party atmosphere and Instagram-worthy setting. Entrance fee includes use of the pools. DJs play during summer afternoons and evenings. The beach club also serves food and cocktails. Located between Bečići and Kamenovo.', '["beach-club", "pools", "trendy"]'::jsonb, '["pools", "dj", "restaurant", "bar", "changing-rooms", "showers"]'::jsonb, '["party", "swimming", "socializing"]'::jsonb, FALSE, 75, TRUE, FALSE, TRUE, FALSE, FALSE, 'rocky', TRUE, FALSE, NULL, 'https://budva.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (37, 'budva-citadela-budva', 'Citadela Budva', '[]'::jsonb, 4, 3, NULL, 42.2886, 18.8375, 'Medieval citadel at the southern tip of Budva''s old town. Houses a library and offers panoramic rooftop views.', 'The medieval citadel occupies the southern tip of Budva''s old town peninsula, offering the highest vantage point within the walls. Built between the 9th and 15th centuries, the fortress now houses a small library and hosts cultural events in its courtyard. The rooftop terrace provides 360-degree panoramic views encompassing the old town, Slovenska Plaža, Sveti Nikola island, and the open Adriatic. A small entrance fee is charged. The citadel''s stone walls and sea views make it one of the best sunset spots in Budva.', '["fortress", "panorama", "medieval"]'::jsonb, '["panoramic-views", "library", "cultural-events"]'::jsonb, '["photography", "sunset", "history"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, FALSE, NULL, 'https://budva.travel/en/fortresses', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (38, 'budva-church-of-santa-maria-in-punta', 'Church of Santa Maria in Punta', '[]'::jsonb, 4, 4, NULL, 42.2891, 18.8381, '9th-century church within the old town walls, one of the oldest sacred buildings on the Adriatic coast.', 'This 9th-century church within Budva''s old town walls is one of the oldest sacred buildings on the Adriatic coast. The simple Romanesque architecture, with its stone walls and modest interior, contrasts with the ornate later churches of the region. The church occasionally hosts classical music concerts and art exhibitions due to its excellent acoustics. Located near the Citadela at the tip of the old town peninsula, it''s easy to visit as part of an old town walk.', '[]'::jsonb, '["concert-venue", "exhibitions"]'::jsonb, '["history", "culture", "architecture"]'::jsonb, TRUE, 55, FALSE, TRUE, FALSE, FALSE, TRUE, NULL, TRUE, FALSE, NULL, 'https://budva.travel/en/churches-and-monasteries', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (39, 'bar-stari-bar-old-bar', 'Stari Bar (Old Bar)', '[]'::jsonb, 5, 3, NULL, 42.0906, 19.1308, 'Impressive medieval fortress city ruins on a hillside 4km from the coast. Over 240 buildings, an aqueduct, churches, and hamam ruins dating to the 6th century.', 'Stari Bar (Old Bar) is one of the most impressive archaeological sites on the Montenegrin coast - a vast medieval fortress city with over 240 buildings spread across a rocky hillside 4 km from modern Bar. Dating from the 6th century, the ruins include churches, mosques, a Turkish bath (hamam), an aqueduct, and residential buildings reflecting centuries of diverse rule. A small museum at the entrance displays artifacts and provides context. The surrounding olive groves include trees over 2,000 years old. Allow 2-3 hours for thorough exploration. Entrance fee approximately 3 EUR.', '["ruins", "medieval", "fortress", "archaeological"]'::jsonb, '["museum", "guided-tours", "souvenir-shop", "parking"]'::jsonb, '["history", "photography", "exploration"]'::jsonb, TRUE, 90, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, TRUE, NULL, 'https://bar.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (40, 'bar-old-olive-tree-of-bar', 'Old Olive Tree of Bar', '[]'::jsonb, 5, 8, NULL, 42.0836, 19.1122, 'One of the oldest olive trees in the world, estimated to be over 2000 years old. A symbol of Bar and a protected natural monument.', 'The Old Olive Tree of Bar is estimated to be over 2,000 years old, making it one of the oldest living trees in Europe and a symbol of the city of Bar. Located in the village of Mirovica between modern Bar and Stari Bar, the tree has a circumference of over 10 meters and still produces olives. A small fence protects the tree, and an information board tells its history. Traditionally, local couples circle the tree before their wedding for good luck. Free to visit; a small olive-themed souvenir shop operates nearby.', '["nature", "ancient", "olive-tree", "unique"]'::jsonb, '["information-board", "souvenir-shop", "free-entry"]'::jsonb, '["history", "nature", "photography"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, TRUE, NULL, 'https://bar.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (41, 'bar-bar-promenade-king-nikola-s-palace', 'Bar Promenade (King Nikola''s Palace)', '[]'::jsonb, 5, 8, NULL, 42.0939, 19.1, 'Seafront promenade area with King Nikola''s Palace (now a museum), botanical garden, and the palace chapel.', 'Bar''s seafront area centers on King Nikola''s Palace, built in 1885, which now houses the local museum with collections of historical artifacts, traditional costumes, and paintings. The surrounding botanical garden features rare plant species collected by the royal family. The palace chapel hosts occasional concerts. The adjacent waterfront promenade extends along the marina, lined with cafes and restaurants. The area is flat and pleasant for walking, connecting the city center with the port area.', '["palace", "museum", "promenade"]'::jsonb, '["museum", "botanical-garden", "chapel", "promenade", "cafes"]'::jsonb, '["history", "walking", "culture"]'::jsonb, TRUE, 65, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, TRUE, NULL, 'https://bar.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (42, 'bar-sutomore-beach', 'Sutomore Beach', '[]'::jsonb, 5, 1, NULL, 42.1439, 19.0417, 'Long sandy beach in the resort town of Sutomore. One of the most popular family beaches on the Montenegrin coast.', 'Sutomore is one of Montenegro''s most popular family beach resorts, featuring a long golden sandy beach backed by pine forests. The resort has a lively summer atmosphere with numerous beach bars, cafes, and restaurants along the promenade. Water sports including jet skiing and banana boats are available. Sutomore is connected to Bar and Podgorica by train (station within walking distance of the beach), making it one of the most accessible beaches in Montenegro. Accommodation options range from hotels to apartments.', '["sandy", "family", "resort"]'::jsonb, '["beach-bars", "restaurants", "water-sports", "train-station", "sunbed-rental", "showers"]'::jsonb, '["families", "swimming", "water-sports"]'::jsonb, TRUE, 80, TRUE, TRUE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://bar.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (43, 'bar-zukotrlica-beach', 'Žukotrlica Beach', '[]'::jsonb, 5, 1, NULL, 42.0778, 19.0953, 'Quiet beach south of Bar, known for its clean water and pebbly shores. Less crowded than city beaches.', 'A quiet pebble beach south of Bar center, known for its exceptionally clean water and lack of crowds. The beach is less developed than the resort beaches, offering a more natural swimming experience. A few small seasonal cafes serve refreshments. The beach is accessible by car or bus from Bar, with limited parking available nearby. Good snorkeling conditions along the rocky edges.', '[]'::jsonb, '["seasonal-cafes", "parking"]'::jsonb, '["swimming", "snorkeling", "tranquility"]'::jsonb, FALSE, 50, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, TRUE, NULL, 'https://bar.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (44, 'bar-canj-beach', 'Čanj Beach', '[]'::jsonb, 5, 1, NULL, 42.1553, 19.0194, 'Sandy beach in the small resort of Čanj. Calm sea, good for families with children.', 'A sandy beach in the small resort of Čanj, located between Sutomore and Petrovac. The beach is known for its calm sea conditions and family-friendly atmosphere, with gradually shelving sand that''s safe for children. Several mini-markets, restaurants, and cafes serve the resort. The quieter atmosphere compared to Sutomore and Budva makes Čanj popular with families seeking a more relaxed holiday. Parking available at the resort.', '[]'::jsonb, '["restaurants", "mini-markets", "parking", "sunbed-rental"]'::jsonb, '["families", "swimming", "relaxation"]'::jsonb, FALSE, 60, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://bar.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (45, 'bar-red-beach-crvena-plaza', 'Red Beach (Crvena Plaža)', '[]'::jsonb, 5, 1, NULL, 42.11, 19.075, 'Distinctive beach with reddish pebbles and sand, surrounded by red-tinted cliffs. Unique geological formation.', 'Red Beach gets its name from the distinctive reddish pebbles and sand derived from the surrounding red-tinted cliffs, creating a unique geological spectacle. The beach is relatively small and less visited, making it ideal for those seeking a unique, uncrowded swimming experience. The unusual color creates striking photographs, especially during golden hour. Access requires a short walk from the nearest road. No commercial facilities on the beach itself.', '["unique", "red-sand", "geological"]'::jsonb, '[]'::jsonb, '["photography", "swimming", "tranquility"]'::jsonb, FALSE, 55, TRUE, TRUE, FALSE, FALSE, FALSE, 'pebble', TRUE, TRUE, NULL, 'https://bar.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (46, 'bar-haj-nehaj-fortress', 'Haj-Nehaj Fortress', '[]'::jsonb, 5, 3, NULL, 42.1422, 19.0478, '15th-century hilltop fortress above Sutomore with panoramic views of the coast. Unique for having both a church and a mosque.', 'Perched on a hilltop above Sutomore at approximately 200 meters elevation, Haj-Nehaj is a 15th-century fortress remarkable for containing both a church and a mosque within its walls - reflecting the region''s layered religious history. The climb from Sutomore takes about 30-40 minutes through Mediterranean scrubland and offers increasingly spectacular panoramic views of the coast, islands, and mountains. The fortress walls are well-preserved, and you can walk the perimeter. Free entry. Best visited in early morning or late afternoon.', '["fortress", "hilltop", "panorama"]'::jsonb, '["panoramic-views", "free-entry"]'::jsonb, '["hiking", "history", "photography"]'::jsonb, TRUE, 60, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, TRUE, NULL, 'https://bar.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (47, 'ulcinj-velika-plaza-long-beach', 'Velika Plaža (Long Beach)', '[]'::jsonb, 6, 1, NULL, 41.9256, 19.2175, '13km stretch of sandy beach, one of the longest on the Adriatic. Known for its dark mineral-rich sand, kitesurfing, and beach bars.', 'At 13 kilometers, Velika Plaža (Long Beach) is one of the longest sandy beaches on the entire Adriatic coast. The dark, mineral-rich sand is believed to have therapeutic properties. The beach is divided into sections, some with full amenities (sunbeds, bars, restaurants) and others completely wild and empty. The northern end near town has the most facilities, while conditions become progressively wilder toward Ada Bojana in the south. Reliable thermal winds from May to September make it one of the Mediterranean''s premier kitesurfing destinations. Multiple kite schools operate along the beach.', '["long-beach", "sandy", "kitesurfing", "iconic"]'::jsonb, '["sunbed-rental", "beach-bars", "restaurants", "kitesurfing-schools", "parking", "showers"]'::jsonb, '["kitesurfing", "beach-walks", "water-sports"]'::jsonb, TRUE, 95, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, TRUE, NULL, 'https://ulcinj.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (48, 'ulcinj-ada-bojana', 'Ada Bojana', '["isola Boiana", "\u0410\u0434\u0430 \u0411\u043e\u0458\u0430\u043d\u0430"]'::jsonb, 6, 1, NULL, 41.8714, 19.2853, 'River island at the border with Albania, famous for its natural nudist beach, fresh fish restaurants, and windsurfing conditions.', 'Ada Bojana is a triangular river island at the confluence of the Bojana River and the Adriatic, straddling the border with Albania. The island is famous for three things: its natural nudist beach (one of Europe''s most well-known), exceptional fresh-fish restaurants along the river, and world-class windsurfing and kitesurfing conditions. The sandy beach on the sea-facing side stretches for 3 km with shallow, warm water. Access is via a bridge from the mainland. Several rustic fish restaurants (čarde) serve river-fresh fish grilled over open flames.', '["island", "naturist", "windsurfing", "river-delta"]'::jsonb, '["restaurants", "naturist-beach", "windsurfing-schools", "kitesurfing", "parking"]'::jsonb, '["windsurfing", "nature", "fresh-fish"]'::jsonb, TRUE, 85, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, TRUE, NULL, 'https://ulcinj.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:06:42');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (49, 'ulcinj-ulcinj-old-town', 'Ulcinj Old Town', '[]'::jsonb, 6, 3, NULL, 41.9289, 19.2064, 'Ancient fortified town on a rocky promontory above the sea. Rich history including Illyrian, Roman, Venetian, and Ottoman periods.', 'Ulcinj''s Old Town is an ancient fortified settlement perched on a rocky promontory above the Adriatic, with a history spanning Illyrian, Roman, Byzantine, Venetian, and Ottoman periods. The fortress walls, some dating to the 5th century, enclose a labyrinth of narrow streets with a distinctive North African feel. Notable sights include the Town Museum (in a former slave market - Ulcinj was once the northernmost slave trading post in the Mediterranean), the Balsic Tower, and several mosques and churches. The sunset views from the fortress walls are among the best in Montenegro.', '["old-town", "fortress", "history", "multicultural"]'::jsonb, '["museum", "restaurants", "panoramic-views", "fortress-walls"]'::jsonb, '["history", "photography", "sunset"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, FALSE, TRUE, NULL, TRUE, TRUE, NULL, 'https://ulcinj.travel/en/attractions', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (50, 'ulcinj-mala-plaza-small-beach', 'Mala Plaža (Small Beach)', '[]'::jsonb, 6, 1, NULL, 41.9281, 19.2072, 'City beach right below the old town walls. Sandy, compact, and with a lively atmosphere during summer.', 'Mala Plaža (Small Beach) is the compact sandy city beach directly below Ulcinj''s old town walls, creating one of the most scenic beach settings in Montenegro. The dark sand is rich in minerals and is said to have healing properties. During summer, the beach has a lively atmosphere with beach bars, sun lounger rental, and waterfront restaurants. The beach is within walking distance of all Ulcinj center accommodations. The medieval fortress walls rising above the beach make for dramatic photographs.', '["city-beach", "sandy", "old-town"]'::jsonb, '["sunbed-rental", "beach-bars", "restaurants", "showers"]'::jsonb, '["swimming", "photography", "convenience"]'::jsonb, FALSE, 70, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://ulcinj.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (51, 'ulcinj-ladies-beach-zenska-plaza', 'Ladies'' Beach (Ženska Plaža)', '[]'::jsonb, 6, 1, NULL, 41.9272, 19.2047, 'Historically a women-only beach with supposedly healing mineral water. Now open to all, with a unique atmosphere.', 'Ženska Plaža (Ladies'' Beach) has a unique history as a women-only bathing spot, where mineral-rich water was traditionally believed to aid fertility and cure various ailments. Now open to all visitors, the small rocky beach retains its distinctive atmosphere and the mineral water still flows. The beach is located a short walk from Mala Plaža, carved into the rocky coastline below the old town. A small entrance fee is charged. The warm mineral spring water mixing with the sea creates a unique swimming experience.', '["unique", "historical", "mineral-water"]'::jsonb, '["mineral-water", "entrance-fee"]'::jsonb, '["wellness", "unique-experience", "swimming"]'::jsonb, FALSE, 55, TRUE, FALSE, FALSE, FALSE, FALSE, 'rocky', FALSE, FALSE, NULL, 'https://ulcinj.travel/en/beaches', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (52, 'ulcinj-sas-lake-sasko-jezero', 'Šas Lake (Šasko Jezero)', '[]'::jsonb, 6, 6, NULL, 41.9583, 19.3167, 'Freshwater lake near Ulcinj, important bird sanctuary and wetland. Great for birdwatching, especially for pelicans.', 'Šasko Jezero (Šas Lake) is a freshwater lake near Ulcinj, serving as an important bird sanctuary and wetland habitat. The lake is home to numerous waterfowl species and is particularly notable for visiting Dalmatian Pelicans, one of the world''s rarest pelican species. The surrounding marshland and reed beds create excellent birdwatching conditions, especially in spring and autumn. The lake is less visited than the Salina, offering a more wild and authentic nature experience. Access is via local roads from the Ulcinj-Shkodër highway.', '["lake", "birdwatching", "nature", "wetland"]'::jsonb, '["birdwatching"]'::jsonb, '["birdwatching", "nature", "tranquility"]'::jsonb, FALSE, 50, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, TRUE, NULL, 'https://ulcinj.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:15', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (53, 'ulcinj-valdanos-olive-grove', 'Valdanos Olive Grove', '[]'::jsonb, 6, 6, NULL, 41.9361, 19.1889, 'Ancient bay with over 80,000 olive trees, one of the largest olive groves on the Adriatic. Beautiful sheltered cove.', 'The Valdanos bay contains over 80,000 olive trees in one of the largest and oldest olive groves on the Adriatic coast. Some trees are centuries old, and the grove has been recognized as a natural monument. The sheltered bay features a small pebble beach with clear water surrounded by the olive-covered hillsides. The area is currently somewhat undeveloped, which preserves its wild beauty. The combination of ancient olive groves, clear swimming water, and untouched nature makes it one of the most unique spots on the Montenegrin coast.', '["olive-grove", "nature", "bay", "ancient"]'::jsonb, '["beach", "nature-walks"]'::jsonb, '["nature", "photography", "tranquility"]'::jsonb, FALSE, 55, TRUE, TRUE, FALSE, FALSE, FALSE, NULL, TRUE, TRUE, NULL, 'https://ulcinj.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:16', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (54, 'ulcinj-ulcinj-salina', 'Ulcinj Salina', '[]'::jsonb, 6, 6, NULL, 41.91, 19.24, 'Former salt production facility, now a key site for birdwatching with over 250 bird species including flamingos and pelicans.', 'The Ulcinj Salina is a former industrial salt production facility that has become one of the most important birdwatching sites in the Mediterranean. Over 250 bird species have been recorded here, including Greater Flamingos, Dalmatian Pelicans, and numerous wading birds. The flat, open landscape provides excellent viewing conditions, and the birds are often visible at relatively close range. The site has been the subject of international conservation efforts. Guided birdwatching tours are available, or visitors can explore independently along the access paths.', '["birdwatching", "flamingos", "nature-reserve", "salina"]'::jsonb, '["guided-tours", "observation-paths", "information-boards"]'::jsonb, '["birdwatching", "nature", "photography"]'::jsonb, TRUE, 70, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://ulcinj.travel/en/nature', 'curated', NULL, NULL, '2026-04-07 21:16:16', '2026-04-09 14:03:12');
