INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (437, 'kotor-konoba-scala-santa', 'Konoba Scala Santa', '["Scala Santa", "Konoba Scala Santa"]'::jsonb, 2, 7, NULL, 42.4248, 18.771, 'Charming old-town seafood restaurant with fisherman-cabin decor. Known for buttery, melt-in-your-mouth sea bass.', 'Konoba Scala Santa is a beloved seafood restaurant located in Kotor''s Old Town, decorated with a fisherman''s aesthetic that makes you feel like you''re dining in the cabin of an old ship. The menu focuses on fresh Adriatic seafood, with the buttery sea bass fillet being a standout signature dish. The intimate stone interior creates a warm and authentic atmosphere. Located on one of the old town''s quieter streets, it offers a respite from the cruise-ship crowds while delivering exceptional quality Montenegrin coastal cuisine.', '["konoba", "seafood", "old-town", "cozy"]'::jsonb, '["indoor-seating", "air-conditioning"]'::jsonb, '["seafood", "romantic-dinner", "authentic-cuisine"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://twopacksandapup.com/10-kotor-restaurants-that-arent-tourist-traps/', 'curated', NULL, NULL, '2026-04-09 13:57:53', '2026-04-09 14:03:12');
