INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (765, 'ulcinj-cickova-carda', 'Ćićkova čarda', '["\u0106i\u0107kova \u010darda", "\u040b\u0438\u045b\u043a\u043e\u0432\u0430 \u0447\u0430\u0440\u0434\u0430"]'::jsonb, 6, 7, NULL, 41.872, 19.286, 'Unique river-island fish restaurant on Ada Bojana. Fresh river and sea fish grilled over open flames in a traditional čarda setting.', 'Ćićkova Čarda is a unique dining experience on Ada Bojana island, where the Bojana River meets the Adriatic. This traditional čarda (riverside tavern) serves some of Montenegro''s best fresh fish - both river catches like carp and trout, and sea fish like sea bass and bream, grilled over open flames. The restaurant sits right at the water''s edge with views over the river and surrounding nature. Fish is typically priced by the kilogram (sea bass around 12-16 EUR/kg, shrimp 15-20 EUR/kg). The rustic, authentic atmosphere and exceptional freshness make it a pilgrimage destination for seafood lovers.', '["fish-restaurant", "river-island", "traditional", "grilled-fish"]'::jsonb, '["parking", "waterfront-seating"]'::jsonb, '["fresh-fish", "authentic-cuisine", "unique-experience", "nature-dining"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://montenegrolimo.com/ada-bojana-best-seafood-and-beach-escape/', 'curated', NULL, NULL, '2026-04-09 13:59:06', '2026-04-09 14:03:13');
