INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (848, 'herceg-novi-dobrec-beach', 'Dobreč Beach', '[]'::jsonb, 1, 1, NULL, 42.387, 18.556, 'Blue Flag sandy beach on the Luštica peninsula, accessible only by boat. Pristine water and untouched Mediterranean beauty.', 'Dobreč is one of the most pristine beaches on the entire Montenegrin coast, earning a Blue Flag designation for its exceptional water quality. Located at the tip of the Luštica Peninsula, it can only be reached by water taxi from Herceg Novi (approximately 10-15 EUR round trip), which keeps crowds manageable even in peak season. The 600-square-meter beach features fine pebbles surrounded by lush vegetation, with a small beach restaurant serving fresh seafood. The crystal-clear water makes it excellent for snorkeling.', '["blue-flag", "boat-access", "pristine", "lustica"]'::jsonb, '["restaurant", "snorkeling"]'::jsonb, '["snorkeling", "swimming", "photography", "tranquility"]'::jsonb, TRUE, 75, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', FALSE, FALSE, NULL, 'https://www.montenegropulse.com/herceg-novi-beaches.html', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (849, 'herceg-novi-njivice-beach', 'Njivice Beach', '[]'::jsonb, 1, 1, NULL, 42.46, 18.495, 'Nearly 1km-long sheltered beach combining sand, pebble, and concrete areas. Less crowded than city beaches with a relaxed atmosphere.', 'Located about 7 km west of Herceg Novi center in the settlement of Njivice, this spacious beach stretches for nearly a kilometer in a sheltered bay. The beach offers a combination of rocky, sandy, and concrete surfaces, giving visitors different swimming options. Regular bus service connects from Herceg Novi''s main bus station for just 1.50 EUR one-way. The sheltered bay provides calm swimming conditions, making it suitable for families with young children.', '["sheltered", "spacious", "bus-accessible"]'::jsonb, '["parking", "bus-access"]'::jsonb, '["swimming", "families", "relaxation"]'::jsonb, FALSE, 55, TRUE, FALSE, FALSE, FALSE, FALSE, 'mixed', TRUE, FALSE, NULL, 'https://www.visit-montenegro.com/destinations/herceg-novi/info/beaches/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (850, 'herceg-novi-konoba-feral', 'Konoba Feral', '[]'::jsonb, 1, 7, NULL, 42.4525, 18.537, 'Family-run stone konoba on the old town waterfront, serving some of the best fresh seafood in the Bay of Kotor.', 'Konoba Feral is a genuine, family-run stone tavern located on the Herceg Novi waterfront near Forte Mare fortress. Built facing the fishing port, the restaurant gets daily deliveries of fresh fish and seafood of undeniable quality. Signature dishes include octopus salad, grilled whole fish, seafood risottos, and traditional Montenegrin soups. The intimate stone interior creates an authentic atmosphere, while the terrace offers views over the bay. A local institution beloved by both residents and visitors seeking traditional coastal dining.', '["konoba", "seafood", "traditional", "waterfront"]'::jsonb, '["outdoor-seating", "waterfront-terrace"]'::jsonb, '["seafood", "romantic-dinner", "authentic-cuisine"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.montenegropulse.com/Herceg-novi-restaurants.html', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (851, 'herceg-novi-konoba-skver', 'Konoba Škver', '[]'::jsonb, 1, 7, NULL, 42.4515, 18.536, 'Historic port-side restaurant where the owner fishes for tuna each morning. Famous for seafood risottos and fresh catch.', 'Nestled right at sea level in Herceg Novi''s charming port, Konoba Škver is a dining institution where the owner is a keen tuna fisherman who often heads out in the morning to seek fresh catch for diners. The restaurant is famous for wonderful traditional seafood risottos - both shrimp-and-saffron and classic black risotto. Squid, octopus, and grilled fish are prepared with simple Mediterranean perfection. The portside location means you dine just meters from the fishing boats that supply the kitchen.', '["konoba", "seafood", "port-side", "fresh-fish"]'::jsonb, '["outdoor-seating", "port-views"]'::jsonb, '["seafood", "local-experience", "lunch"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.montenegropulse.com/Herceg-novi-restaurants.html', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (852, 'herceg-novi-tondo-club-bar', 'Tondo Club & Bar', '[]'::jsonb, 1, 8, NULL, 42.453, 18.534, 'Year-round music venue near the city park with marina views. Known for smooth house music, reggae, and drum & bass nights.', 'Tondo is Herceg Novi''s premier year-round music venue, located near the city park with a stunning view of the marina. The club is known for playing quality music with a focus on smooth house, while also featuring reggae and drum & bass nights. The atmosphere is laid-back yet energetic, attracting a mix of locals and visitors. The outdoor terrace overlooking the bay makes it particularly atmospheric during summer evenings.', '["club", "house-music", "marina-view", "year-round"]'::jsonb, '[]'::jsonb, '["nightlife", "live-music", "cocktails"]'::jsonb, FALSE, 70, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://evendo.com/locations/montenegro/herceg-novi/best-bars', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (853, 'herceg-novi-la-bamba-beach-club', 'La Bamba Beach Club', '[]'::jsonb, 1, 8, NULL, 42.45, 18.532, 'Beachfront club for cocktails and live DJ sets. Dance barefoot on the sand with bay views and Mediterranean breezes.', 'La Bamba Beach Club is a popular seaside nightlife spot in Herceg Novi, perfect for those who want to combine beach vibes with evening entertainment. The club offers cocktails and live DJ sets against the backdrop of the Bay of Kotor. During summer evenings the energy builds from sunset cocktails to late-night dancing barefoot on the sand. The venue strikes a balance between relaxed beach bar and lively party spot.', '["beach-club", "dj", "cocktails", "bay-views"]'::jsonb, '[]'::jsonb, '["sunset-drinks", "dancing", "beach-party"]'::jsonb, FALSE, 65, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://emapark.com/discover-herceg-novis-nightlife/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (854, 'herceg-novi-adriatic-blue-diving-center', 'Adriatic Blue Diving Center', '[]'::jsonb, 1, 9, NULL, 42.452, 18.5372, 'SSI-certified dive center operating since 2003. Explore the Tihany shipwreck, Mamula Island underwater sites, and the Blue Cave.', 'Adriatic Blue is the only SSI-certified dive center in Montenegro and has operated since 2003 from Herceg Novi''s City Port Skver. They offer daily fun dives, wreck diving (including the famous Tihany shipwreck near Mamula Island), cave diving, and night dives. Introductory dives are available for beginners, and full certification courses for adults and children. The Mamula Island dive sites plunge to 30 meters and feature excellent marine diversity alongside fascinating Austro-Hungarian military history.', '["diving", "PADI", "SSI", "wreck-diving", "adventure"]'::jsonb, '["equipment-rental", "certified-instructors", "courses"]'::jsonb, '["diving", "snorkeling", "adventure", "certification"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, TRUE, FALSE, NULL, FALSE, FALSE, NULL, 'https://divingmontenegro.com/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (855, 'herceg-novi-pet-danica-promenade-setaliste-pet-danica', 'Pet Danica Promenade (Šetalište Pet Danica)', '[]'::jsonb, 1, 10, NULL, 42.456, 18.52, '6km seaside promenade stretching from Igalo through Herceg Novi to Meljine. Perfect for families with stalls, cafes, and shoreline views.', 'The Pet Danica Promenade is a beloved 6-kilometer coastal path stretching from Igalo through Herceg Novi center to the neighborhood of Meljine. The flat, paved walkway passes numerous cafes, restaurants, souvenir stalls, and swimming spots along the way. At the Igalo end near Tito''s Villa, shallow sandy water and an abundance of crabs and fish make it a favorite spot for children of all ages. The promenade is stroller-friendly and offers constant views of the bay, making it one of the best family outings in the region.', '["promenade", "seaside", "walking", "family"]'::jsonb, '["cafes", "restaurants", "stroller-friendly", "flat-path"]'::jsonb, '["families", "walking", "sunset-stroll", "kids"]'::jsonb, TRUE, 75, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, TRUE, NULL, 'https://www.montenegropulse.com/herceg-novi-montenegro.html', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (856, 'kotor-dobrota-beach', 'Dobrota Beach', '[]'::jsonb, 2, 1, NULL, 42.435, 18.775, '7km waterfront stretch north of the old town with concrete and pebble sections. Peaceful setting with stunning bay views.', 'Dobrota''s seafront extends 7 kilometers north along the coastal road from Kotor''s Old Town, offering a mix of concrete swimming platforms and natural pebble sections. The village is peaceful and surrounded by untouched nature, with crystal-clear waters and beautiful views across the Bay of Kotor. Several waterfront cafes and restaurants dot the shoreline, and the gentle walk from the Old Town takes about 20 minutes. The sheltered bay provides calm swimming conditions throughout the season from mid-May to October.', '["waterfront", "village", "calm-water", "walking-distance"]'::jsonb, '["cafes", "restaurants", "parking"]'::jsonb, '["swimming", "walking", "relaxation"]'::jsonb, FALSE, 55, TRUE, FALSE, FALSE, FALSE, FALSE, 'mixed', TRUE, FALSE, NULL, 'https://www.kotordirectory.com/listing-category/attractions/beaches-waterfronts/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (857, 'kotor-stoliv-beach', 'Stoliv Beach', '[]'::jsonb, 2, 1, NULL, 42.465, 18.72, 'Quiet concrete beach in a charming 14th-century village whose name means ''one hundred olives''. Peaceful and uncrowded.', 'The beautiful leafy village of Stoliv dates back to the 14th century, with its name meaning ''one hundred olives'' reflecting the ancient olive groves that surround it. The small concrete beach has no commercial infrastructure but many nearby cafes and restaurants serve visitors. Located 10-15 km from Kotor, it is reachable by car or bicycle along the scenic bay road. A parking lot and pier provide easy access. Stoliv is one of the quietest and least-visited swimming spots in the Bay of Kotor, making it ideal for those seeking tranquility.', '["village", "quiet", "historic", "olive-trees"]'::jsonb, '["parking", "pier", "cafes-nearby"]'::jsonb, '["tranquility", "swimming", "cycling-stop"]'::jsonb, FALSE, 40, TRUE, FALSE, FALSE, FALSE, FALSE, 'rocky', TRUE, FALSE, NULL, 'http://www.montenegrofortravellers.com/en/review/beaches-kotor-and-risan-bay', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (858, 'kotor-catovica-mlini', 'Ćatovića Mlini', '[]'::jsonb, 2, 7, NULL, 42.4862, 18.65, 'Legendary restaurant in a centuries-old stone mill in Morinj village. Dine among ancient stone arches beside a mountain stream.', 'Ćatovića Mlini is consistently rated as one of Montenegro''s top restaurants, set in a centuries-old stone mill in the tiny village of Morinj. The Catovic family has used these mills for over 200 years, and in the last 25 years transformed the site into an extraordinary dining destination. You dine among ancient stone arches with a mountain stream flowing through the restaurant. Seafood dominates the menu, with fresh catches prepared in traditional Boka Bay style. Open 12:00-21:30. Reservations strongly recommended in summer.', '["fine-dining", "historic", "stone-mill", "stream-side"]'::jsonb, '["parking", "outdoor-seating", "historic-setting"]'::jsonb, '["special-occasion", "seafood", "romantic-dinner", "photography"]'::jsonb, TRUE, 95, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.catovica-mlini.com/en/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (859, 'kotor-maximus-nightclub', 'Maximus Nightclub', '[]'::jsonb, 2, 8, NULL, 42.424, 18.77, 'One of the largest nightclubs in Montenegro with 4,000 person capacity. International DJs, techno, house, and pop music year-round.', 'Maximus is one of the most famous nightclubs not only in Kotor but in all of Montenegro. Located just outside the Old Town walls, this massive venue has a capacity of up to 4,000 people, attracting both locals and tourists with its high-energy atmosphere. The club regularly hosts local and international DJs covering techno, house, pop, and hip-hop genres. Operating year-round, it transforms from summer open-air parties to indoor winter events. The venue''s proximity to the Old Town makes it the natural culmination of a Kotor night out.', '["nightclub", "large-venue", "international-djs", "year-round"]'::jsonb, '[]'::jsonb, '["nightlife", "dancing", "dj-events"]'::jsonb, TRUE, 85, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.visit-montenegro.com/destinations/kotor/info/night-clubs/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (860, 'kotor-letrika-bar', 'Letrika Bar', '[]'::jsonb, 2, 8, NULL, 42.4245, 18.7715, 'Atmospheric side-alley bar in Kotor''s Old Town. Quiet daytime drinks transform into vibrant DJ nights with dancing in the street.', 'Letrika occupies a side alley in Kotor''s Old Town, offering a quiet spot for a drink during the day that transforms completely on summer nights. When darkness falls, the narrow alley gets jammed with young people dancing and sipping cocktails while DJs perform from the tiny venue, spilling their beats into the cobblestone street. The contrast between its daytime calm and nighttime energy makes it one of Kotor''s most unique nightlife experiences. Cocktail prices are reasonable by Old Town standards.', '["bar", "old-town", "dj", "alley-bar", "cocktails"]'::jsonb, '[]'::jsonb, '["nightlife", "cocktails", "atmosphere"]'::jsonb, FALSE, 70, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://twopacksandapup.com/kotor-nightlife-the-best-bars-in-old-town/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (861, 'kotor-blue-cave-kayak-adventure', 'Blue Cave Kayak Adventure', '[]'::jsonb, 2, 9, NULL, 42.3889, 18.5594, 'Guided kayak tours to the Blue Cave and surrounding sea caves. No experience needed; gear and safety briefing provided.', 'Several operators (Montenegro+, Adventure Montenegro) offer guided kayak tours to the Blue Cave and surrounding sea caves from departure points near Muo and the Luštica Peninsula. The tours use stable inflatable sit-on-top kayaks suitable for complete beginners, with guides providing detailed safety briefings before setting off. Half-day tours cover approximately 6 km of paddling with stops for snorkeling, departing at 10 AM and 3 PM. Prices start at around 20 EUR per person. Kayaks can access smaller caves that speedboats cannot reach.', '["kayaking", "blue-cave", "guided-tour", "snorkeling", "adventure"]'::jsonb, '["equipment-provided", "guides", "snorkel-gear"]'::jsonb, '["adventure", "kayaking", "snorkeling", "photography"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, TRUE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.montenegroplus.me/blue-cave-kayak', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (862, 'kotor-vrmac-peninsula-mountain-biking', 'Vrmac Peninsula Mountain Biking', '[]'::jsonb, 2, 9, NULL, 42.44, 18.73, 'Mountain biking tours on the Vrmac ridge between Kotor and Tivat. Reach Fort Vrmac at 480m and Saint Ilija peak at 760m for panoramic views.', 'The Vrmac Peninsula offers premier mountain biking with tours starting from Trojica pass, climbing 4km on road to the Austro-Hungarian Fort Vrmac at 480 meters, then continuing off-road to Saint Ilija peak at 760 meters. Saint Ilija is unique in the Bay of Kotor as the only point from which you can see the entire bay. Guided tours last approximately 3 hours with 2 hours of cycling and include short walks into old forts. The strenuous ascend tour requires significant MTB experience, while moderate-difficulty options with more downhill segments are also available.', '["mountain-biking", "vrmac", "panorama", "fort", "adventure"]'::jsonb, '["bike-rental", "guides", "helmets"]'::jsonb, '["mountain-biking", "adventure", "panoramic-views", "fitness"]'::jsonb, FALSE, 75, FALSE, FALSE, FALSE, TRUE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.montenegroplus.me/vrmac-mtb-tour', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (863, 'tivat-oblatno-beach', 'Oblatno Beach', '[]'::jsonb, 3, 1, NULL, 42.3811, 18.6647, 'Scenic Luštica peninsula beach home to the famous Almara Beach Club. Pebble shores with turquoise water and full-service amenities.', 'Oblatno Beach is a beautiful pebble beach on the Luštica Peninsula, best known as the home of the Almara Beach Club. The beach offers sun loungers, umbrellas, and full restaurant and bar service, making it one of the most well-equipped beaches in the Tivat area. The turquoise water is excellent for swimming, and the beach transforms into a nightlife venue after sunset with DJ sets and themed parties. Accessible by car from Tivat (approximately 15 minutes) with parking available. The beach is also accessible from Luštica Bay resort.', '["beach-club", "lustica", "amenities", "nightlife"]'::jsonb, '["sunbed-rental", "restaurant", "bar", "parking", "changing-rooms", "showers"]'::jsonb, '["sunbathing", "swimming", "sunset", "beach-party"]'::jsonb, TRUE, 80, TRUE, FALSE, TRUE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://www.beachatlas.com/oblatno', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (864, 'tivat-one-restaurant-bar', 'ONE Restaurant & Bar', '[]'::jsonb, 3, 7, NULL, 42.4352, 18.6918, 'Porto Montenegro''s flagship restaurant since 2011. Contemporary Adriatic-Continental cuisine with an international wine list.', 'ONE was established in 2011 as the first restaurant in Porto Montenegro''s superyacht marina and remains a magnet for yachties, expats, and stylish visitors from across the region. The menu features local, seasonal, and frequently refreshed contemporary Adriatic-Continental cuisine paired with an excellent international wine list. The waterfront terrace offers prime marina views, and the interior is sleek and modern. Rated 4.3/5 on TripAdvisor and ranked among the top restaurants in Tivat. Ideal for a refined lunch or dinner with marina ambiance.', '["fine-dining", "porto-montenegro", "marina", "wine"]'::jsonb, '["outdoor-terrace", "marina-views", "air-conditioning", "wine-list"]'::jsonb, '["fine-dining", "marina-views", "wine", "special-occasion"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.myguidemontenegro.com/restaurants/one', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (865, 'tivat-prova-restaurant', 'Prova Restaurant', '[]'::jsonb, 3, 7, NULL, 42.4345, 18.6925, 'Ship-shaped building on Tivat''s promenade with bay-view rooftop dining. Contemporary cuisine for breakfast, lunch, and dinner.', 'Prova is located on the main promenade in central Tivat, housed in a distinctive building shaped like a ship. The restaurant offers seating on the seafront terrace or the rooftop, both overlooking the bay. The menu features contemporary Mediterranean cuisine suitable for any meal of the day. The unique architectural design, combined with panoramic bay views from the rooftop, makes it one of Tivat''s most distinctive dining experiences. Popular with both visitors and locals, it serves as an excellent starting point for an evening walk along the waterfront.', '["contemporary", "rooftop", "bay-views", "ship-building"]'::jsonb, '["rooftop-terrace", "waterfront", "air-conditioning"]'::jsonb, '["bay-views", "rooftop-dining", "casual-dining"]'::jsonb, FALSE, 70, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://gokii.digital/best-restaurants-tivat/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (866, 'tivat-almara-beach-club', 'Almara Beach Club', '[]'::jsonb, 3, 8, NULL, 42.3815, 18.665, 'Premier beach club on the Luštica Peninsula. Upscale daytime lounging transforms into DJ nights and themed parties after sunset.', 'Almara Beach Club on the Luštica Peninsula (Oblatno beach) is one of Montenegro''s most prestigious beach clubs. During the day it offers premium sun lounger service, excellent Mediterranean cuisine, and crystal-clear swimming waters. After sunset, Almara transforms into a nightlife hotspot with live DJs, themed parties, and expertly crafted cocktails. The club attracts a mix of locals, marina guests from nearby Luštica Bay, and visitors from across the bay. Events range from chill sunset sessions to high-energy weekend parties.', '["beach-club", "dj", "lustica", "upscale", "cocktails"]'::jsonb, '["sunbed-rental", "restaurant", "bar", "parking", "dj-events"]'::jsonb, '["beach-party", "sunset-drinks", "nightlife", "cocktails"]'::jsonb, TRUE, 80, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://lusticabay.com/lustica-bay-beach/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (867, 'tivat-buddha-bar-tivat', 'Buddha-Bar Tivat', '[]'::jsonb, 3, 8, NULL, 42.4355, 18.691, 'Luxury lounge bar in Porto Montenegro with international DJs, bay views, and a blend of upscale nightlife and beach-club vibes.', 'Part of the global Buddha-Bar franchise, this Porto Montenegro outpost is the perfect blend of luxury and laid-back beach club vibes, set right by the stunning Bay of Kotor. International DJs take over as the sun goes down, turning the place into a buzzing nightclub. The venue features an extensive cocktail menu, Asian-fusion cuisine, and distinctive Buddha-Bar decor. The waterfront setting within the marina village provides beautiful backdrop of superyachts and bay views. Popular for both pre-dinner cocktails and late-night entertainment.', '["lounge", "porto-montenegro", "luxury", "international-dj"]'::jsonb, '[]'::jsonb, '["nightlife", "cocktails", "luxury-experience"]'::jsonb, FALSE, 75, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.portomontenegro.com/blog/montenegro-nightlife-guide-all-you-need-to-know/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (868, 'tivat-scaramanga-bar', 'Scaramanga Bar', '[]'::jsonb, 3, 8, NULL, 42.435, 18.6915, 'Elegant marina-side cocktail bar in Porto Montenegro. Signature cocktails with stunning yacht and bay views.', 'Scaramanga Bar is an elegant cocktail venue within Porto Montenegro''s marina village, combining signature cocktails with stunning views of yachts and the Bay of Kotor. The bar attracts a stylish crowd and is perfect for a romantic evening or a gathering with friends. The menu features creative cocktails alongside a curated wine and spirits selection. The outdoor terrace offers prime marina-watching, while the interior provides a more intimate setting. It sits at the heart of Porto Montenegro''s evening scene.', '["cocktail-bar", "porto-montenegro", "marina", "elegant"]'::jsonb, '[]'::jsonb, '["cocktails", "romantic-evening", "marina-views"]'::jsonb, FALSE, 70, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://emapark.com/exploring-tivat-nightlife/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (869, 'tivat-lustica-bay-water-sports-center', 'Luštica Bay Water Sports Center', '[]'::jsonb, 3, 9, NULL, 42.39, 18.67, 'Water sports center on the Luštica Peninsula offering kayaking, SUP, and snorkeling with guided coastal excursions.', 'The water sports center at Luštica Bay resort offers kayaking, stand-up paddleboarding (SUP), and snorkeling experiences along the stunning Luštica Peninsula coastline. Guided excursions explore hidden coves, sea caves, and crystal-clear swimming spots inaccessible by road. Equipment is provided for all activities, and no prior experience is necessary for most programs. The calm, sheltered waters of the bay make conditions ideal for beginners. SUP yoga sessions and sunset paddle tours are available during peak season.', '["kayaking", "SUP", "snorkeling", "water-sports", "guided"]'::jsonb, '["equipment-provided", "guides", "beginner-friendly"]'::jsonb, '["kayaking", "SUP", "snorkeling", "families"]'::jsonb, FALSE, 65, TRUE, FALSE, FALSE, TRUE, FALSE, NULL, TRUE, FALSE, NULL, 'https://lusticabay.com/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (870, 'tivat-island-of-flowers-nature-trail', 'Island of Flowers Nature Trail', '[]'::jsonb, 3, 10, NULL, 42.4115, 18.6826, 'Easy family walk through the botanical peninsula with medieval monastery ruins, exotic plants, and bay views. Connected by a short bridge.', 'The Island of Flowers (Miholjska Prevlaka) is a small peninsula connected to the mainland by a short bridge, making it an ideal family excursion from Tivat. The easy walking trail winds through diverse Mediterranean and exotic plant species, past medieval monastery ruins, and offers continuous bay views. The flat, well-maintained paths are suitable for strollers and young walkers. There are shaded areas for picnics and benches along the route. The combination of nature, history, and gentle exercise makes it one of the best family-friendly activities in Tivat.', '["family", "nature-trail", "botanical", "monastery", "easy-walk"]'::jsonb, '["benches", "shade", "flat-paths", "stroller-friendly"]'::jsonb, '["families", "nature-walk", "kids", "photography"]'::jsonb, FALSE, 75, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, TRUE, NULL, 'https://tivat.travel/en/nature', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (871, 'budva-drobni-pijesak-beach', 'Drobni Pijesak Beach', '[]'::jsonb, 4, 1, NULL, 42.2341, 18.9042, 'Hidden sandy beach between Sveti Stefan and Petrovac with fine golden sand, a natural freshwater spring, and unspoiled tropical feel.', 'Drobni Pijesak (meaning ''Crushed Sand'') is a 250-meter hidden beach located between Sveti Stefan and Petrovac on the Budva Riviera. The beach features fine yellow-white sand and smooth pebbles giving it a tropical feel, and is considered one of Montenegro''s best ''wild beaches'' - unspoiled yet welcoming. A natural freshwater spring nearby is an uncommon and refreshing feature for a seaside location. There is a small beach bar and restaurant, plus a mooring platform for diving into the Adriatic. Access is via a steep path from the main road, about 7.8 km from Budva center.', '["hidden-beach", "sandy", "wild", "freshwater-spring", "tropical"]'::jsonb, '["beach-bar", "restaurant", "parking"]'::jsonb, '["swimming", "tranquility", "snorkeling", "photography"]'::jsonb, FALSE, 70, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://sandee.com/montenegro/budva/drobnici/drobni-pijesak-beach', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (872, 'budva-przno-beach', 'Pržno Beach', '[]'::jsonb, 4, 1, NULL, 42.2686, 18.8924, 'Charming 350m beach in a fishing village backed by olive groves. West-facing for spectacular sunsets. Mix of sand and rocky sections.', 'Pržno is a combination of partly sandy and partly rocky beach stretching 350 meters in a traditional fishing village between Budva and Sveti Stefan. The beach is backed by olive groves of extreme ecological value, making the entire locality a protected natural reservation. Facing west, the sunset here is particularly spectacular. The village maintains its authentic fishing character with several excellent seafood restaurants right on the waterfront. Less developed than Budva''s main beaches, Pržno offers a more authentic Montenegrin coastal experience.', '["fishing-village", "sunset", "olive-groves", "authentic"]'::jsonb, '["restaurants", "parking"]'::jsonb, '["sunset", "photography", "authentic-experience", "dining"]'::jsonb, FALSE, 65, TRUE, FALSE, FALSE, FALSE, FALSE, 'mixed', TRUE, FALSE, NULL, 'https://www.montenegropulse.com/budva-beaches.html', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (873, 'budva-konoba-stari-grad', 'Konoba Stari Grad', '[]'::jsonb, 4, 7, NULL, 42.289, 18.838, 'Traditional konoba tucked behind stone walls in Budva''s Old Town. Family-run, with own-brewed beer, live music, and summer beach seating.', 'Tucked away behind a stone facade in Budva''s old town, Konoba Stari Grad epitomizes coastal Montenegrin dining. The family-run restaurant serves traditional Montenegrin cuisine including whole fish with dalmatinsko varivo (Dalmatian-style silver beet and potato with garlic), and also brews its own beer. An intimate stone interior creates an authentic atmosphere, while in summer you can take a table on the beach. A live musician serenades diners in the evening, completing the traditional Montenegrin dining experience.', '["konoba", "old-town", "live-music", "craft-beer", "traditional"]'::jsonb, '["outdoor-seating", "beach-tables", "live-music"]'::jsonb, '["traditional-food", "live-music", "romantic-dinner", "local-experience"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://theculturetrip.com/europe/montenegro/articles/the-10-best-restaurants-in-budva-montenegro', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (874, 'budva-jadran-kod-krsta', 'Jadran Kod Krsta', '[]'::jsonb, 4, 7, NULL, 42.2885, 18.839, 'Seaside institution for over 40 years, with tables on the sand. Famous for the fish plate for two, fresh catch, and local wine.', 'Jadran Kod Krsta is one of the oldest and most established restaurants in Budva, serving traditional coastal cuisine for over 40 years from its prime seaside promenade location. Whole fish, octopus, calamari, and shellfish are all excellent here, prepared simply with a squeeze of lemon, garlic, parsley, and paired with local red wine. The idyllic setting features tables directly on the sand, and the fish plate for two is the signature recommendation. Live rock music occasionally accompanies the dining experience, creating a uniquely Budva atmosphere.', '["seafood", "seaside", "institution", "40-years"]'::jsonb, '["beach-seating", "seaside-terrace"]'::jsonb, '["seafood", "romantic-dinner", "sunset-dining"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://www.montenegropulse.com/best-budva-restaurants.html', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (875, 'budva-dukley-beach-bar', 'Dukley Beach & Bar', '[]'::jsonb, 4, 7, NULL, 42.283, 18.851, 'Upscale beach dining between Budva and Bečići with fine sand, champagne bar, and innovative ''New Mediterranean'' cuisine.', 'Dukley Beach & Bar is an urban oasis offering three beach sections: the upscale VIP Beach, the sandy Moet et Chandon Beach, and the Lagoon Beach. The restaurant features a cantilevered terrace over the beach and serves innovative ''New Mediterranean'' cuisine with a focus on fresh, simple dishes perfect for lunch and sharing. The champagne and cocktail bar adds a touch of luxury to the beach experience. Part of the Dukley Hotels collection, it represents the premium end of Budva''s beach dining scene with comfortable sunbeds and attentive service.', '["upscale", "beach-bar", "new-mediterranean", "champagne", "luxury"]'::jsonb, '["sunbed-rental", "champagne-bar", "restaurant", "vip-section", "showers"]'::jsonb, '["upscale-dining", "beach-luxury", "cocktails", "sunbathing"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.dukleyhotels.com/en/dining/dukley-beach-bar', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (876, 'budva-top-hill', 'Top Hill', '[]'::jsonb, 4, 8, NULL, 42.2938, 18.8223, 'The largest and most famous open-air nightclub in the Balkans, perched on Topliš hill at 160m elevation with Adriatic panoramic views.', 'Top Hill is the crown jewel of Montenegrin nightlife, an open-air mega-club perched on Topliš hill at 160 meters elevation overlooking Budva and the Adriatic. With a massive dance floor, state-of-the-art sound and lighting systems, and multiple bars, it regularly hosts world-famous international DJs. The club operates during summer season (June-September) with events typically starting around midnight and running until dawn. Located about 2 km from Budva center via Topliški put, shuttles and taxis are readily available. VIP tables and bottle service available.', '["mega-club", "open-air", "international-dj", "panoramic", "iconic"]'::jsonb, '["parking", "vip-area", "multiple-bars", "shuttle-service"]'::jsonb, '["nightlife", "dancing", "dj-events", "panoramic-views"]'::jsonb, TRUE, 95, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.tophill.me/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (877, 'budva-club-sparta', 'Club Sparta', '[]'::jsonb, 4, 8, NULL, 42.2895, 18.8385, 'Stylish and intimate nightclub near the Old Town with ancient-themed decor. Curated electronic, R&B, and house music lineup.', 'Club Sparta brings a unique atmosphere to Budva''s nightlife with its ancient-themed decor and carefully curated music lineup ranging from electronic to R&B and house. Located near the Old Town, the stylish and intimate venue attracts a trendy, upscale crowd looking for a more exclusive night out compared to the mega-clubs. The club features VIP areas and a quality sound system in a more personal setting. Popular as either a warm-up venue before Top Hill or as the main destination for those preferring a more refined clubbing experience.', '["nightclub", "upscale", "themed-decor", "intimate"]'::jsonb, '[]'::jsonb, '["nightlife", "upscale-clubbing", "cocktails"]'::jsonb, FALSE, 70, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://twopacksandapup.com/budva-nightlife-breakdown-all-the-top-spots-to-party/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (878, 'budva-budva-paragliding-from-brajici', 'Budva Paragliding from Brajići', '[]'::jsonb, 4, 9, NULL, 42.27, 18.82, 'Tandem paragliding from 765m above sea level. Soar over Sveti Stefan, Bečići, and the island of Sveti Nikola with expert pilots.', 'Multiple certified operators (Go2fly, Budva Paragliding since 1993, Paragliding Montenegro) offer tandem paragliding flights launching from Brajići at 765 meters above sea level, with landings near Bečići beach. Flights last 15-30+ minutes depending on conditions, offering panoramic views over Sveti Stefan, Miločer, Bečići, Budva, and the island of Sveti Nikola. No previous experience is required - each passenger flies with their own certified pilot. The activity is suitable for individuals, couples, families, or groups. GoPro video footage is typically available as an add-on.', '["paragliding", "tandem", "adventure", "panoramic", "adrenaline"]'::jsonb, '["certified-pilots", "transport-to-launch", "photo-video"]'::jsonb, '["adventure", "panoramic-views", "adrenaline", "photography"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, TRUE, FALSE, NULL, FALSE, FALSE, NULL, 'https://budva-paragliding.me/', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (879, 'budva-sveti-nikola-island-hawaii', 'Sveti Nikola Island (Hawaii)', '[]'::jsonb, 4, 10, NULL, 42.285, 18.845, 'Car-free island opposite Budva accessible by water taxi. Three beaches, a small church, deer roaming freely, and a relaxed family atmosphere.', 'Sveti Nikola Island, affectionately nicknamed ''Hawaii'' by locals, is the largest island on the Montenegrin coast, sitting just opposite Budva. Water taxis run regularly from Budva, Bečići, and Slovenska Plaža during summer (approximately 3-5 EUR). The car-free island features three beaches (pebble and rocky), a small medieval church, and a population of deer that roam freely. The island offers a peaceful escape from Budva''s summer bustle, with beach bars and restaurants operating during the season. The shallow waters on the Budva-facing side are ideal for children.', '["island", "car-free", "water-taxi", "deer", "family"]'::jsonb, '["beach-bars", "restaurants", "water-taxi"]'::jsonb, '["families", "day-trip", "swimming", "nature"]'::jsonb, TRUE, 80, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://budva.travel/en/attractions', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (880, 'budva-petrovac-beach', 'Petrovac Beach', '[]'::jsonb, 4, 1, NULL, 42.2083, 18.9306, 'Charming 600m red-pebble beach in the resort town of Petrovac. Venetian fortress, offshore islands, and a lively promenade with pine trees.', 'Petrovac Beach is a 600-meter stretch of distinctive red pebbles in the charming resort town of Petrovac, about 17 km south of Budva. The beach is flanked by a Venetian fortress (Castello) at one end and offers views of two small offshore islands - Sveta Nedjelja and Katič with its tiny chapel. A lively promenade lined with pine trees, restaurants, and shops runs behind the beach. The calm, crystal-clear turquoise waters are ideal for swimming and snorkeling, and the gentle entry makes it family-friendly. Pine trees provide natural shade along the edges of the beach.', '["resort", "red-pebble", "fortress", "islands", "promenade"]'::jsonb, '["restaurants", "shops", "sunbed-rental", "water-sports", "parking", "showers"]'::jsonb, '["families", "swimming", "promenade-walks", "snorkeling"]'::jsonb, TRUE, 80, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://www.montenegropulse.com/budva-beaches.html', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (881, 'bar-maljevik-beach', 'Maljevik Beach', '[]'::jsonb, 5, 1, NULL, 42.138, 19.035, '300m pebble beach near Sutomore with health-beneficial mud and clay. Partly naturist, with a beach restaurant and basic amenities.', 'Maljevik is a distinctive 300-meter beach near Sutomore, about 10 km from Bar, known for its health-beneficial mud and clay deposits. The main surface consists of small pebbles with rocks and some trees providing natural shade. The far end of the beach is reserved for naturists. Access requires descending concrete steps about 25 meters to the beach, with a dirt parking area just meters from the top. A beach restaurant serves hamburgers, pizza, and ćevapi, with changing rooms, showers, toilets, and a beach bar completing the basic amenities.', '["naturist", "healing-mud", "secluded", "pebble"]'::jsonb, '["restaurant", "changing-rooms", "showers", "toilets", "beach-bar", "parking"]'::jsonb, '["tranquility", "naturism", "wellness", "swimming"]'::jsonb, FALSE, 50, TRUE, FALSE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://www.beachrex.com/en/montenegro/bar/sutomore-beaches/beach-maljevik', 'curated', NULL, NULL, '2026-04-09 14:03:12', '2026-04-09 14:03:12');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (882, 'bar-utjeha-beach', 'Utjeha Beach', '[]'::jsonb, 5, 1, NULL, 42.115, 19.065, 'Scenic family beach in Oliva bay surrounded by olive trees. Mix of sand and pebbles with crystal-clear turquoise waters.', 'Utjeha is a scenic stretch of coastline in Oliva bay, known for its rugged beauty and family-friendly conditions. Surrounded by olive trees and Mediterranean vegetation, the beach features a mix of sand and pebbles with crystal-clear turquoise waters. The sheltered bay provides calm swimming conditions ideal for families with children. Several small restaurants and apartments dot the coastline. Located between Bar and Ulcinj, Utjeha offers a quieter alternative to the busier resort beaches while still providing basic amenities and services.', '["olive-trees", "family", "turquoise", "sheltered"]'::jsonb, '["restaurants", "parking", "apartments-nearby"]'::jsonb, '["families", "swimming", "relaxation", "quiet-holiday"]'::jsonb, FALSE, 55, TRUE, FALSE, FALSE, FALSE, FALSE, 'mixed', TRUE, FALSE, NULL, 'https://www.visit-montenegro.com/destinations/bar/info/beaches/', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (883, 'bar-dobra-voda-beach', 'Dobra Voda Beach', '[]'::jsonb, 5, 1, NULL, 42.105, 19.055, '600m sandy beach in a charming coastal village between Bar and Ulcinj. Calm, private atmosphere with water sports and beach bars.', 'Dobra Voda is a charming coastal village approximately 10 km south of Bar, nestled between lush hills and the crystal-clear Adriatic Sea. The main beach stretches approximately 600 meters of sandy shore with water sports facilities available in season. Compared to Sutomore''s busy resort atmosphere, Dobra Voda offers a more calm and private beach experience. Modest nightlife centers around beach bars and restaurants that occasionally feature live music in summer. The village is a favorite with visitors seeking an authentic, less commercialized Montenegrin coastal experience.', '["village", "sandy", "calm", "authentic"]'::jsonb, '["water-sports", "beach-bars", "restaurants", "parking"]'::jsonb, '["relaxation", "families", "authentic-experience"]'::jsonb, FALSE, 50, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://www.dobra-voda.com/', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (884, 'bar-parapet-pizza-grill', 'Parapet Pizza & Grill', '[]'::jsonb, 5, 7, NULL, 42.094, 19.1, 'Year-round coastal promenade restaurant in Bar, a favorite among locals. Pizza, grilled meats, and seafood with sea views.', 'Parapet Pizza & Grill is located along Bar''s coastal promenade and remains open year-round, making it a rare reliable dining option outside peak season. The restaurant is a favorite among both locals and visitors, serving excellent pizza, grilled meats, and fresh seafood. The promenade setting provides sea views and a pleasant atmosphere for dining. Near King Nikola''s Palace and the city marina, it serves as a convenient stop during a waterfront exploration of Bar. The menu offers good value with generous portions.', '["year-round", "promenade", "pizza", "grill", "local-favorite"]'::jsonb, '["outdoor-seating", "sea-views"]'::jsonb, '["casual-dining", "pizza", "year-round-dining"]'::jsonb, FALSE, 65, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.tripadvisor.com/Restaurants-g608961-Bar_Bar_Municipality.html', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (885, 'bar-sutomore-beach-bar-strip', 'Sutomore Beach Bar Strip', '[]'::jsonb, 5, 8, NULL, 42.144, 19.042, 'Vibrant beachfront nightlife strip in Sutomore with bars, live music, and summer concerts. Popular with young travelers.', 'Sutomore''s beachfront comes alive at night during summer with a vibrant strip of bars, clubs, and live music venues lining the sandy beach. The resort town is known for its energetic nightlife, featuring everything from cocktail bars with coastal views to open-air venues hosting live concerts and DJ sets. The nightlife scene is particularly popular among young travelers and locals, with drinks priced affordably at 3-6 EUR. The atmosphere peaks in July and August when the beach bars extend their hours deep into the night.', '["beach-bars", "live-music", "summer-nightlife", "affordable"]'::jsonb, '[]'::jsonb, '["nightlife", "live-music", "beach-party", "budget-friendly"]'::jsonb, FALSE, 65, FALSE, TRUE, TRUE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://montenegro.org/sutomore-the-small-coastal-town-in-montenegro/', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (886, 'bar-stari-bar-hiking-trail', 'Stari Bar Hiking Trail', '[]'::jsonb, 5, 9, NULL, 42.091, 19.131, 'Scenic hike through olive groves to the medieval fortress ruins of Stari Bar. Explore 240+ ancient buildings, an aqueduct, and hamam.', 'The trail to Stari Bar (Old Bar) takes hikers through centuries-old olive groves, including some trees over 2,000 years old, up to the impressive medieval fortress ruins perched on a hillside 4 km from the coast. The archaeological site contains over 240 buildings, a well-preserved aqueduct, churches from various periods, and Ottoman hamam (bathhouse) ruins dating to the 6th century. The moderate hike takes about 30-45 minutes from the lower parking area. The fortress offers panoramic views over modern Bar, the coast, and Lake Skadar in the distance. Early morning or late afternoon visits are recommended to avoid summer heat.', '["hiking", "medieval-ruins", "olive-groves", "archaeology", "panorama"]'::jsonb, '["parking", "guided-tours-available", "museum-on-site"]'::jsonb, '["hiking", "history", "photography", "exploration"]'::jsonb, TRUE, 80, FALSE, FALSE, FALSE, TRUE, TRUE, NULL, TRUE, TRUE, NULL, 'https://bar.travel/en/attractions', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (887, 'bar-sutomore-family-beach-zone', 'Sutomore Family Beach Zone', '[]'::jsonb, 5, 10, NULL, 42.144, 19.0415, 'Sandy family beach zone in Sutomore with shallow warm water, pine tree shade, and nearby playgrounds. One of Montenegro''s top family destinations.', 'Sutomore''s family beach zone occupies the central portion of the resort''s long sandy beach, offering ideal conditions for families with young children. The sandy bottom and gradually deepening water create a safe swimming environment, while pine forests behind the beach provide natural shade for picnics and rest. The beach has full facilities including sunbed rental, cafes, restaurants, and nearby playgrounds. Sutomore is connected by train from Bar and Podgorica, making it one of the most accessible beach resorts for families traveling without a car. Accommodations range from hotels to family apartments directly behind the beach.', '["family", "sandy", "pine-trees", "train-accessible", "shallow-water"]'::jsonb, '["sunbed-rental", "cafes", "restaurants", "playgrounds", "shade", "train-station"]'::jsonb, '["families", "kids", "swimming", "budget-holiday"]'::jsonb, FALSE, 75, TRUE, TRUE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.visit-montenegro.com/destinations/bar/info/beaches/', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (888, 'ulcinj-valdanos-beach', 'Valdanos Beach', '[]'::jsonb, 6, 1, NULL, 41.937, 19.19, 'Sheltered bay beach surrounded by 80,000 olive trees. Pebble shores with clear water in one of the largest olive groves on the Adriatic.', 'Valdanos is a beautiful sheltered cove surrounded by one of the largest olive groves on the Adriatic, containing over 80,000 olive trees. The pebble beach offers clear swimming water in a setting of remarkable natural beauty. The bay is well-protected from winds, making swimming conditions reliably calm. Currently less developed than other Ulcinj beaches, Valdanos retains a wild, unspoiled character. Access is via a winding road from the main highway, and parking is available near the beach. A few small seasonal restaurants operate during summer months.', '["olive-grove", "sheltered", "nature", "unspoiled"]'::jsonb, '["parking", "seasonal-restaurants"]'::jsonb, '["swimming", "nature", "tranquility", "photography"]'::jsonb, FALSE, 55, TRUE, TRUE, FALSE, FALSE, FALSE, 'pebble', TRUE, FALSE, NULL, 'https://ulcinj.travel/en/nature', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (889, 'ulcinj-copacabana-beach', 'Copacabana Beach', '[]'::jsonb, 6, 1, NULL, 41.926, 19.21, 'Central sandy resort beach near Ulcinj town with full amenities, water sports, and a lively summer atmosphere.', 'Copacabana is a well-equipped sandy beach located near Ulcinj town center, bridging the gap between the compact Mala Plaža and the vast Velika Plaža. The beach offers full resort-style amenities including sunbed and umbrella rental, water sports, beach bars, and restaurants. The sandy bottom and moderate depth make it suitable for families, while the beach bars create a lively atmosphere during summer evenings. Copacabana is easily walkable from Ulcinj''s old town and most accommodations, making it the most convenient well-serviced beach option in the area.', '["sandy", "resort", "amenities", "central"]'::jsonb, '["sunbed-rental", "water-sports", "beach-bars", "restaurants", "parking", "showers"]'::jsonb, '["swimming", "water-sports", "families", "convenience"]'::jsonb, FALSE, 65, TRUE, FALSE, FALSE, FALSE, FALSE, 'sandy', TRUE, FALSE, NULL, 'https://ulcinj.travel/en/beaches', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (890, 'ulcinj-antigona-restaurant', 'Antigona Restaurant', '[]'::jsonb, 6, 7, NULL, 41.929, 19.206, 'Old town restaurant with panoramic sea views from the fortress walls. Fresh Adriatic seafood and traditional Albanian-Montenegrin cuisine.', 'Antigona Restaurant is perched within Ulcinj''s ancient Old Town fortress walls, offering dramatic panoramic views over the Adriatic Sea. The menu blends traditional Albanian and Montenegrin coastal cuisine with a strong focus on fresh Adriatic seafood. Grilled fish, octopus, and regional specialties reflect Ulcinj''s unique multicultural culinary heritage. The terrace dining experience at sunset, with views stretching to the horizon, is among the most memorable in southern Montenegro. The restaurant captures the distinctive east-meets-west character that defines Ulcinj''s food scene.', '["old-town", "panoramic", "seafood", "multicultural"]'::jsonb, '["terrace", "sea-views", "fortress-setting"]'::jsonb, '["sunset-dining", "seafood", "panoramic-views", "romantic-dinner"]'::jsonb, TRUE, 75, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://ulcinj.travel/en/restaurants', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (891, 'ulcinj-dolcinium-club', 'Dolcinium Club', '[]'::jsonb, 6, 8, NULL, 41.928, 19.206, 'Open-air club near the Old Town where you dance under the stars. The hub of Ulcinj''s summer nightlife scene.', 'Named after Ulcinj''s Latin name ''Dulcinium'', this open-air club is the centerpiece of Ulcinj''s nightlife scene. Located near the Old Town, the venue offers dancing under the stars with a mix of regional and international music. The club attracts both locals and visitors, creating an energetic multicultural atmosphere that reflects Ulcinj''s Albanian-Montenegrin character. Summer evenings start with relaxed cocktails and build to peak energy around midnight. Drinks are affordably priced at 3-6 EUR, making it accessible for a wide range of visitors.', '["open-air", "dancing", "multicultural", "affordable"]'::jsonb, '[]'::jsonb, '["nightlife", "dancing", "budget-nightlife"]'::jsonb, FALSE, 65, FALSE, FALSE, TRUE, FALSE, FALSE, NULL, FALSE, FALSE, NULL, 'https://resort-austria.com/ulcinj-after-dark-best-spots-for-nightlife-cocktails-sunset-views/', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (892, 'ulcinj-kiteriders-kitesurfing-center', 'Kiteriders Kitesurfing Center', '[]'::jsonb, 6, 9, NULL, 41.91, 19.22, 'IKO-certified kitesurfing center on Velika Plaža. Reliable thermal winds May-September on 14km of sandy beach with perfect beginner conditions.', 'Kiteriders is a premier kitesurfing center located directly on Velika Plaža (Long Beach), which stretches over 14 km and is never crowded. Reliable thermal wind systems guarantee optimal kitesurfing conditions from May through September, with consistent side-onshore winds perfect for learning. Beginners find ideal conditions with a wide standing area of sandy bottom in shallow water. The center is IKO-certified and offers lessons at all levels from complete beginners to advanced riders. Equipment rental is available for experienced kitesurfers. Multiple other schools (Dragon Project, Kiteloop, Sandbox) also operate on the beach, reflecting its reputation as one of the Mediterranean''s premier kite spots.', '["kitesurfing", "IKO-certified", "velika-plaza", "wind-sports", "beginner-friendly"]'::jsonb, '["equipment-rental", "certified-instructors", "beginner-zone", "changing-rooms"]'::jsonb, '["kitesurfing", "windsurfing", "beginners", "water-sports"]'::jsonb, TRUE, 85, FALSE, FALSE, FALSE, TRUE, FALSE, NULL, TRUE, FALSE, NULL, 'https://www.kitesurfing-montenegro.com/', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
INSERT INTO places (id, slug, name, alternate_names, municipality_id, category_id, subtype, lat, lng, short_description, long_description, tags, amenities, best_for, featured, popularity_score, family_friendly, hidden_gem, nightlife, active_holiday, cultural_site, beach_type, parking_available, pet_friendly, accessibility_notes, source_url, source_type, license_type, verified_at, created_at, updated_at) VALUES (893, 'ulcinj-ulcinj-salina-birdwatching-trail', 'Ulcinj Salina Birdwatching Trail', '[]'::jsonb, 6, 10, NULL, 41.91, 19.24, 'Family-friendly birdwatching at a former salt pan. Over 250 species including flamingos and pelicans in a unique wetland habitat.', 'The Ulcinj Salina (former salt production facility) is one of the most important birdwatching sites in the Mediterranean, hosting over 250 bird species including Greater Flamingos, Dalmatian Pelicans, and numerous wading birds. The flat terrain and maintained observation paths make it accessible for families with children of all ages, and the colorful flamingos are a hit with young visitors. Binoculars are recommended but not essential as many birds can be observed at relatively close range. The best viewing times are early morning and late afternoon, especially during spring and autumn migration seasons. Entry is free, and basic information panels explain the species and habitat.', '["birdwatching", "flamingos", "nature-reserve", "wetland", "educational"]'::jsonb, '["observation-paths", "information-panels", "free-entry"]'::jsonb, '["birdwatching", "families", "nature", "photography", "education"]'::jsonb, FALSE, 70, TRUE, FALSE, FALSE, FALSE, FALSE, NULL, TRUE, FALSE, NULL, 'https://ulcinj.travel/en/nature', 'curated', NULL, NULL, '2026-04-09 14:03:13', '2026-04-09 14:03:13');
